// PulseUnit — Lexique médical (260+ termes, 13 catégories).
// Extrait d'index.html (était aux lignes 1783-2082).
// Expose window.LEXIQUE_DATA pour cohabiter avec les scripts inline d'index.html
// pendant la migration vers l'architecture feature-based.

  window.LEXIQUE_DATA = [
/* ===== PERSONNEL ===== */
{ term:"Présence temps réel", fullName:"Suivi de connexion en direct", def:"Fonctionnalité PulseUnit affichant dans le panel admin la liste des utilisateurs actuellement connectés à l’application, avec leur rôle et l’heure de dernière activité.", expert:"Mise à jour automatique via Firebase onSnapshot. Chaque connexion/déconnexion/fermeture de page met à jour le statut. Utile pour l’admin afin de savoir qui est actif sur l’app en cours de garde.", cat:"PERSONNEL"},
{ term:"PIN Code", fullName:"Code d’accès à 6 chiffres", def:"Code numérique personnel permettant l’authentification sécurisée dans PulseUnit. Hashé en SHA-256 côté client, jamais stocké en clair.", expert:"En cas d’oubli : utiliser ‘Code oublié ?’ → l’admin reçoit la demande et génère un code provisoire. À remplacer immédiatement lors de la 1ère connexion avec le code provisoire. Après 3 erreurs, le compte est bloqué.", cat:"PERSONNEL"},
{ term:"Compte bloqué", fullName:"Blocage sécurité après échecs PIN", def:"Mécanisme de protection qui bloque un compte utilisateur après 3 codes PIN erronés consécutifs.", expert:"Le déblocage se fait dans le panneau admin (liste des comptes) via le bouton 🔓, ou lors de la génération d’un code provisoire.", cat:"PERSONNEL"},
{ term:"Session admin", fullName:"Connexion administrateur séparée", def:"Mode administrateur activé via identifiants admin dans l’écran de connexion, distinct du compte personnel.", expert:"Permet d’ouvrir le panneau admin et de consulter l’ensemble de l’app en lecture globale. Les attributions de lits restent non modifiables en session admin.", cat:"PERSONNEL"},
{ term:"Mode lecture seule", fullName:"Accès consultation sans modification", def:"Mode d’accès activé automatiquement si l’utilisateur n’est pas affecté à la garde en cours. Consultation possible, aucune modification permise.", expert:"Utile pour consulter l’historique des gardes passées ou vérifier les affectations sans risque de modification accidentelle. Les outils (lexique, calculateurs, protocoles) restent accessibles.", cat:"PERSONNEL"},
{ term:"IDE", fullName:"Infirmier Diplômé d’État", def:"Professionnel responsable de la réalisation des soins prescrits, de la surveillance continue des paramètres vitaux et de l’administration des thérapeutiques.", expert:"En réanimation, l’IDE doit anticiper les défaillances d’organes, interpréter les monitorages complexes (scope, respirateur, PiCCO) et agir rapidement sur prescription ou en rôle propre.", cat:"PERSONNEL"},
{ term:"AS", fullName:"Aide-Soignant", def:"Professionnel assurant les soins d’hygiène, de confort et participant à la surveillance clinique du patient sous la responsabilité de l’IDE.", expert:"Rôle clé en réa : prévention des escarres (mobilisation, matelas), kinésithérapie de confort, aide aux transferts lourds, surveillance des signes d’alerte à remonter à l’IDE.", cat:"PERSONNEL"},
{ term:"MED", fullName:"Médecin Réanimateur", def:"Responsable de la stratégie diagnostique et thérapeutique des patients critiques. Prescrit et supervise l’ensemble des soins.", expert:"Décide des gestes invasifs (intubation, pose CVC, drainage), ajuste les supports d’organes (ventilation, catécholamines, épuration) et coordonne l’équipe pluridisciplinaire.", cat:"PERSONNEL"},
{ term:"TECH", fullName:"IDE Technique", def:"Infirmier dédié à la logistique, aux urgences internes et à la gestion des dispositifs complexes en réanimation.", expert:"Assure la disponibilité du matériel critique (chariot urgences, circuits respiratoires, fibro), intervient en assistance lors des gestes invasifs et gère les commandes de dispositifs médicaux.", cat:"PERSONNEL"},
{ term:"IADE", fullName:"Infirmier Anesthésiste DE", def:"Infirmier spécialisé en anesthésie-réanimation, intervenant lors d’actes anesthésiques ou d’urgences vitales.", expert:"Compétence spécifique sur l’intubation difficile, la gestion des VAS et les protocoles d’anesthésie. Ressource précieuse lors des intubations complexes en réa.", cat:"PERSONNEL"},
{ term:"Transmission", fullName:"Transmission infirmière — temps réglementaire", def:"Temps de passation entre deux équipes permettant le transfert des informations cliniques, thérapeutiques et organisationnelles concernant chaque patient. Droit légal de 15 min (0,25h) par jour travaillé.", expert:"Les heures de transmission s'accumulent et peuvent être récupérées. Calcul : 0,25h × nombre de jours travaillés. PulseUnit intègre un calculateur dédié dans les Calculateurs. Transmission efficace = S.B.A.R. (Situation, Background, Assessment, Recommendation).", cat:"PERSONNEL"},
{ term:"Kiné", fullName:"Kinésithérapeute de réanimation", def:"Professionnel de santé assurant la rééducation respiratoire et motrice des patients de réanimation.", expert:"Intervient sur le désencombrement bronchique, la VNI, la mobilisation précoce et la prévention des complications de décubitus (pneumopathie, amyotrophie).", cat:"PERSONNEL"},
{ term:"Normes de référence", fullName:"Tables de normes cliniques PulseUnit", def:"Module de consultation rapide regroupant 6 catégories de valeurs de référence : Vitaux, GDS, Ventilation, Biologie, Dialyse et Urines. Tables statiques optimisées pour la pratique IDE/AS en réanimation.", expert:"Sources : SFAR 2024, SRLF, KDIGO 2024, ESC/AHA 2023, ARDSNet, ESICM. Accessible via Menu ☰ → Normes. Vitaux : FC, PAS/PAD/PAM, FR, SpO₂, T°, Glasgow. GDS : pH, PaO₂, PaCO₂, HCO₃⁻, BE, lactates, rapport P/F + stades SDRA. Ventilation : paramètres réglés + pressions. Biologie : NFS, ionogramme, rein, foie, coag, inflammation. Dialyse : stades AKI KDIGO, paramètres CVVH/CVVHD, anticoagulation. Urines : oligurie, polyurie, analyse urinaire.", cat:"PERSONNEL"},
/* ===== MONITORAGE ===== */
{ term:"Scope", fullName:"Monitoring multiparamétrique", def:"Système de surveillance continue regroupant ECG, SpO2, pression artérielle, fréquence respiratoire et température.", expert:"Individualiser les seuils d’alarme pour chaque patient afin d’éviter la fatigue d’alarme (alarm fatigue). Une alarme ignorée = risque vital.", cat:"MONITORAGE"},
{ term:"ECG", fullName:"Électrocardiogramme", def:"Enregistrement continu de l’activité électrique cardiaque permettant l’analyse du rythme, de la conduction et de la repolarisation.", expert:"En réa : détection immédiate d’arythmies (FA, TV, FV), troubles conductifs (BAV), signes d’ischémie (sus-décalage ST) ou d’hyperkaliémie (onde T pointue, QRS larges).", cat:"MONITORAGE"},
{ term:"SpO2", fullName:"Saturation pulsée en oxygène", def:"Mesure non invasive de la saturation de l’hémoglobine en oxygène. Objectif 94-98% (92-96% si BPCO).", expert:"Faussée par : vasoconstriction périphérique, hypothermie, vernis à ongles, anémie sévère, intoxication CO (SpO2 faussement normale). Toujours corréler aux GDS en cas de doute.", cat:"MONITORAGE"},
{ term:"TA invasive", fullName:"Pression artérielle invasive", def:"Mesure continue de la pression artérielle via un cathéter artériel (radiale le plus souvent), couplé à un capteur de pression.", expert:"Mise à zéro obligatoire au niveau de l’oreillette droite. Permet les prélèvements artériels pour GDS. Surveiller le site d’insertion (ischémie distale).", cat:"MONITORAGE"},
{ term:"PVC", fullName:"Pression Veineuse Centrale", def:"Pression mesurée en veine cave supérieure via le CVC, reflet partiel du remplissage du coeur droit. Valeur normale : 2-8 mmHg.", expert:"Valeur isolée peu fiable pour guider le remplissage. Interpréter en dynamique et avec l’échographie cardiaque.", cat:"MONITORAGE"},
{ term:"EtCO2", fullName:"Capnographie - CO2 expiré", def:"Mesure du CO2 en fin d’expiration (end-tidal CO2). Valeur normale : 35-45 mmHg. Confirme le bon positionnement de la sonde d’intubation.", expert:"Chute brutale d’EtCO2 = arrêt circulatoire ou obstruction de sonde. Augmentation = hypoventilation. Indispensable lors de toute intubation.", cat:"MONITORAGE"},
{ term:"PiCCO", fullName:"Pulse index Contour Cardiac Output", def:"Monitoring hémodynamique avancé mesurant le débit cardiaque, le volume sanguin intrathoracique (ITBV) et l’eau pulmonaire extravasculaire (EVLWI).", expert:"Nécessite KT artériel fémoral + CVC. Utile pour guider le remplissage (EVLWI) et les catécholamines (IC, RVS). Calibrage régulier par thermodilution requis.", cat:"MONITORAGE"},
{ term:"SvO2 / ScvO2", fullName:"Saturation veineuse en oxygène", def:"SvO2 = saturation veineuse mêlée (artère pulmonaire). ScvO2 = saturation veineuse cave supérieure (CVC). Reflet de l’équilibre apport/consommation en O2.", expert:"ScvO2 normale >= 70%. Valeur basse = extraction augmentée (choc, anémie). Valeur haute paradoxale = mauvaise extraction tissulaire (choc septique évolué, shunts).", cat:"MONITORAGE"},
{ term:"Température", fullName:"Surveillance thermique continue", def:"Mesure continue de la température centrale (sonde rectale, vésicale ou nasopharyngée). Valeur normale : 36.5-37.5°C.", expert:"Hyperthermie > 38.5°C = rechercher foyer infectieux. Hypothermie < 36°C = risque coagulopathie, arythmies. Objectif normothermie stricte post-ACR.", cat:"MONITORAGE"},
{ term:"Diurèse", fullName:"Diurèse horaire — Débit urinaire", def:"Volume d'urine produit par heure, rapporté au poids corporel. Valeur normale : 0,5 à 1,5 mL/kg/h. Indicateur direct de la perfusion rénale et du bilan hydrique.", expert:"Oligurie < 0,5 mL/kg/h : IRA fonctionnelle (hypovolémie) ou organique (nécrose tubulaire). Anurie < 0,1 mL/kg/h : urgence — vérifier sondage, puis bilan rénal complet. Polyurie > 2,5 mL/kg/h : phase polyurique post-IRA, diabète insipide, diurétiques. Surveiller natrémie, kaliémie et osmolarité urinaire. Bilan entrées/sorties strict en réa.", cat:"MONITORAGE"},
{ term:"FR", fullName:"Fréquence Respiratoire", def:"Nombre de cycles respiratoires par minute. Valeur normale adulte : 12-20/min. Paramètre vital simple mais souvent sous-évalué — prédicteur précoce de dégradation.", expert:"Bradypnée < 12/min : dépression respiratoire (opiacés, lésion centrale). Tachypnée > 25/min : signe d'alarme majeur — détresse respiratoire, sepsis, acidose métabolique, douleur. La FR est le premier paramètre à s'élever lors d'une dégradation clinique. Toujours mesurer sur 1 minute complète, en observation discrète (le patient modifie sa FR s'il le sait observé).", cat:"MONITORAGE"},
{ term:"FC", fullName:"Fréquence cardiaque", def:"Nombre de contractions cardiaques par minute. Normale : 60-100 bpm. Surveillance continue sur le scope.", expert:"Tachycardie > 100 = douleur, fièvre, hypovolémie, TEP, arythmie. Bradycardie < 50 = BAV, hyperkaliémie, bêtabloquants. Toujours chercher la cause.", cat:"MONITORAGE"},
/* ===== NEURO ===== */
{ term:"BIS", fullName:"Index Bispectral", def:"Indice dérivé de l’EEG évaluant la profondeur de la sédation. Valeur de 0 (silence cortical) à 100 (éveil complet).", expert:"Cible en sédation profonde : 40-60. < 40 = surdosage possible. > 70 = risque de conscience. Peut être faussé par EMI ou hypothermie. Complément du RASS.", cat:"NEURO"},
{ term:"Glasgow", fullName:"Score de Glasgow (GCS)", def:"Score neurologique coté de 3 à 15 évaluant l’ouverture des yeux (Y), la réponse verbale (V) et la réponse motrice (M). GCS <= 8 = indication d’intubation.", expert:"En réa : documenter les composantes séparément (ex: Y2V1M4). Un GCS <= 8 impose la protection des voies aériennes. Surveiller les modifications dans le temps.", cat:"NEURO"},
{ term:"CAM-ICU", fullName:"Confusion Assessment Method for ICU", def:"Outil de dépistage du delirium en réanimation. Évalue : début aigu, inattention, désorganisation de la pensée, niveau de conscience.", expert:"Delirium = facteur de risque indépendant de mortalité et de troubles cognitifs. Rechercher causes (sepsis, médicaments, douleur, désorientation). Appliquer le bundle ABCDEF.", cat:"NEURO"},
{ term:"Bundle ABCDEF", fullName:"Bundle ABCDEF — Réhabilitation précoce en réanimation", def:"Ensemble de 6 interventions coordonnées visant à réduire le delirium, la durée de ventilation mécanique et les séquelles cognitives du séjour en réanimation.", expert:"A = Analgésie optimale (CPOT/BPS). B = Awakening trials + Breathing trials spontanés quotidiens. C = Choice of sedation (RASS -1 à 0 sauf indication). D = Delirium (dépistage CAM-ICU, prévention). E = Early mobility (lever précoce, exercice au lit). F = Family engagement (présence des proches réduit le delirium). Chaque composante réduit la mortalité et la durée de séjour. Ne pas négliger F.", cat:"SCORES"},
{ term:"Pupilles", fullName:"Examen pupillaire", def:"Évaluation du réflexe photo-moteur, de la taille (myosis/mydriase) et de la symétrie pupillaire. Indicateur d’atteinte du tronc cérébral.", expert:"Mydriase bilatérale aréactive = engagement cérébral ou intoxication. Myosis serré = opiacés. Anisocorie = atteinte du III homolatérale. À évaluer toutes les heures en neuro-réa.", cat:"NEURO"},
{ term:"PIC", fullName:"Pression Intracrânienne", def:"Pression à l’intérieur de la boîte crânienne. Normale < 15 mmHg. Mesurée par capteur intraparenchymateux ou ventriculostomie.", expert:"HTIC si PIC > 20 mmHg. PPC = PAM - PIC, objectif >= 60-70 mmHg. Traitement : position 30°, osmothérapie (Mannitol), sédation, hyperventilation transitoire.", cat:"NEURO"},
/* ===== SCORES ===== */
{ term:"RASS", fullName:"Richmond Agitation Sedation Scale", def:"Échelle de sédation/agitation de -5 (sédation profonde) à +4 (combatif). Score 0 = patient éveillé et calme. Standard de titration de la sédation en réanimation.", expert:"Cible habituelle : RASS -1 à 0. RASS -4/-5 pour curarisation ou SDRA sévère. Évaluation toutes les 2-4H. Toujours coupler à l’évaluation douleur (CPOT/BPS).", cat:"SCORES"},
{ term:"CPOT", fullName:"Critical Pain Observation Tool", def:"Échelle d’évaluation de la douleur chez le patient non communicant (0 à 8). Évalue : expression faciale, mouvements corporels, tension musculaire, compliance au ventilateur.", expert:"CPOT >= 3 = douleur significative -> adapter l’analgésie. À évaluer avant et après tout geste douloureux. Documenter systématiquement avec l’heure et la réponse thérapeutique.", cat:"SCORES"},
{ term:"BPS", fullName:"Behavioral Pain Scale", def:"Échelle de douleur pour patient non communicant (3 à 12). Évalue : expression faciale (1-4), mouvements des membres supérieurs (1-4), compliance au ventilateur (1-4).", expert:"BPS >= 6 = douleur non contrôlée. Alternative au CPOT selon les protocoles de service. L’analgésie est prioritaire sur la sédation (concept Analgesia First).", cat:"SCORES"},
{ term:"SOFA", fullName:"Sequential Organ Failure Assessment", def:"Score mesurant la défaillance de 6 organes (respi, coag, foie, cardio, neuro, rénal) de 0 à 4 par organe. Total : 0-24. Suivi du patient septique.", expert:"SOFA >= 2 points par rapport au score basal = critère diagnostique du sepsis. Augmentation = aggravation. Corrélé à la mortalité. À calculer quotidiennement.", cat:"SCORES"},
{ term:"SAPS II", fullName:"Simplified Acute Physiology Score II", def:"Score de gravité calculé dans les 24 premières heures d’admission (17 variables). Prédit la probabilité de mortalité hospitalière.", expert:"Score > 50 associé à une mortalité élevée. Utilisé à des fins épidémiologiques et de benchmarking. Ne pas l’utiliser pour des décisions individuelles de prise en charge.", cat:"SCORES"},
{ term:"NRS", fullName:"Numeric Rating Scale (douleur)", def:"Échelle numérique d’autoévaluation de la douleur de 0 (pas de douleur) à 10 (douleur maximale imaginable). Utilisée chez le patient communicant.", expert:"NRS >= 4 = douleur modérée nécessitant une adaptation thérapeutique. Évaluation systématique au repos, lors des mobilisations et après chaque acte. Tracer dans le dossier.", cat:"SCORES"},
{ term:"Score Norton", fullName:"Score d’évaluation du risque d’escarre", def:"Score de 5 à 20 évaluant le risque de développer une escarre (état général, mental, activité, mobilité, incontinence).", expert:"Score <= 14 = risque élevé -> matelas anti-escarres, repositionnement toutes les 2-3H, évaluation cutanée quotidienne. Rôle essentiel de l’AS.", cat:"SCORES"},
/* ===== VENTILATION ===== */
{ term:"Respirateur", fullName:"Ventilateur mécanique", def:"Appareil assurant la ventilation artificielle du patient en cas d’insuffisance respiratoire. Peut fonctionner en mode contrôlé ou assisté.", expert:"Réglages essentiels : VT (6 ml/kg PP), PEEP (5-15 cmH2O), FiO2, FR. Vérifier les alarmes, les condensats dans les circuits, le bon positionnement de la sonde. Check-list quotidienne.", cat:"VENTILATION"},
{ term:"VNI", fullName:"Ventilation Non Invasive", def:"Support ventilatoire par masque (facial ou nasal) délivrant une aide inspiratoire et une pression expiratoire. Évite l’intubation dans certaines situations.", expert:"Indiquée : OAP cardiogénique, décompensation BPCO, sevrage ventilatoire. Contre-indiquée : coma, vomissements, détresse sévère. Surveiller les fuites et les irritations cutanées.", cat:"VENTILATION"},
{ term:"Optiflow", fullName:"Oxygénothérapie à Haut Débit (OHD)", def:"Administration d’oxygène humidifié et chauffé à des débits élevés (15-70 L/min) via canules nasales. Génère une PEEP physiologique légère.", expert:"Améliore le confort et rince l’espace mort anatomique. Ne doit pas retarder l’intubation si dégradation clinique. Surveiller la fréquence respiratoire et la SpO2.", cat:"VENTILATION"},
{ term:"BAVU", fullName:"Ballon Auto-remplisseur à Valve Unidirectionnelle", def:"Dispositif manuel de ventilation utilisé en urgence (ACR, transport) ou lors du débranchement du respirateur.", expert:"Toujours connecté à O2 (10-15 L/min) en réanimation. Vérifier l’étanchéité du masque et l’expansion thoracique à chaque insufflation.", cat:"VENTILATION"},
{ term:"Compliance", fullName:"Compliance pulmonaire statique", def:"Capacité du poumon et de la cage thoracique à se distendre sous l'effet d'une pression. Calculée par C = VT / (Pplat - PEEP). Normale : 50-100 mL/cmH₂O.", expert:"Compliance réduite = poumon rigide (SDRA, OAP, fibrose, atélectasie). Compliance élevée = emphysème, BPCO. En pratique : ΔP élevée pour un VT donné = compliance basse. Pplat - PEEP > 20 cmH₂O pour 6 mL/kg PP = compliance < 30 mL/cmH₂O = SDRA sévère.", cat:"VENTILATION"},
{ term:"PEEP", fullName:"Positive End-Expiratory Pressure", def:"Pression positive maintenue dans les poumons en fin d’expiration pour maintenir les alvéoles ouvertes et améliorer les échanges gazeux.", expert:"PEEP élevée améliore l’oxygénation mais diminue le retour veineux -> risque d’hypotension. Auto-PEEP possible en cas d’obstruction bronchique (BPCO, asthme). Vérifier au manomètre.", cat:"VENTILATION"},
{ term:"PEEPi / Auto-PEEP", fullName:"PEEP intrinsèque — Piège gazeux", def:"Pression positive résiduelle dans les poumons en fin d’expiration, non réglée sur le respirateur. Résulte d’un temps expiratoire insuffisant pour vider complètement les poumons.", expert:"Mesure : pause expiratoire au manomètre. Risques : hyperinflation dynamique → hypotension (↓ retour veineux) + barotraumatisme. Contexte typique : BPCO, asthme aigu grave, tachypnée sévère, obstruction bronchique. Correction : allonger le temps expiratoire (↓ FR, ↑ rapport I:E), traiter le bronchospasme. En urgence : débranchement bref du respirateur pour décompression.", cat:"VENTILATION"},
{ term:"VT", fullName:"Volume Courant (Tidal Volume)", def:"Volume d’air insufflé à chaque cycle ventilatoire. Cible protectrice : 6 ml/kg de poids idéal prédit (4-8 ml/kg selon le contexte).", expert:"VT élevé = volutraumatisme. VT bas = hypercapnie tolérée si pH > 7.20. Calculer systématiquement selon le poids idéal prédit, jamais le poids réel.", cat:"VENTILATION"},
{ term:"FiO2", fullName:"Fraction inspirée en oxygène", def:"Proportion d’oxygène dans le mélange inspiré. De 21% (air ambiant) à 100% (O2 pur). Réglée directement sur le respirateur.", expert:"FiO2 100% acceptable en urgence courte durée. Éviter > 60% prolongée (toxicité : atélectasies d’absorption). Objectif SpO2 92-96% (94-98% hors BPCO).", cat:"VENTILATION"},
{ term:"Pplat", fullName:"Pression de plateau", def:"Pression mesurée en fin d’insufflation lors d’une pause inspiratoire. Reflet de la pression alvéolaire. Objectif : <= 30 cmH2O.", expert:"Pplat > 30 cmH2O = risque de barotraumatisme (pneumothorax). Si élevée : diminuer VT, PEEP, ou chercher une cause (bronchospasme, bouchon muqueux, pneumothorax).", cat:"VENTILATION"},
{ term:"Driving Pressure", fullName:"Pression motrice (Delta P)", def:"Différence entre la pression de plateau et la PEEP totale (Pplat - PEEP). Reflet de la contrainte mécanique sur le parenchyme pulmonaire aéré.", expert:"Delta P > 15 cmH2O associé à une surmortalité dans le SDRA. Objectif <= 14 cmH2O. Calculable depuis les réglages du respirateur.", cat:"VENTILATION"},
{ term:"IOT", fullName:"Intubation orotrachéale", def:"Mise en place d’une sonde dans la trachée par voie orale pour sécuriser et contrôler les voies aériennes et assurer la ventilation mécanique.", expert:"Vérification : auscultation bilatérale, EtCO2, radiographie de thorax (tip sonde à 2-3 cm de la carène). Fixer la sonde et noter le repère en cm aux arcades dentaires. Gonflage ballonnet 20-30 cmH2O.", cat:"VENTILATION"},
{ term:"VS-AI", fullName:"Ventilation Spontanée avec Aide Inspiratoire", def:"Mode ventilatoire assisté où le patient déclenche lui-même le respirateur, qui amplifie chaque inspiration. Favorise le sevrage ventilatoire.", expert:"Permet le maintien de l’activité diaphragmatique. Surveiller le VT spontané, la fréquence, la synchronisation patient-machine. Clé du sevrage progressif.", cat:"VENTILATION"},
{ term:"SDRA", fullName:"Syndrome de Détresse Respiratoire Aiguë", def:"Insuffisance respiratoire aiguë hypoxémiante définie par un rapport PaO2/FiO2 < 300, des opacités bilatérales et une origine non cardiogénique pure.", expert:"SDRA sévère P/F < 100 -> décubitus ventral 16H/j (réduit mortalité). VT 6 ml/kg PP. PEEP optimisée. Curarisation 48H si P/F < 150. Éviter la surcharge hydrique.", cat:"VENTILATION"},
{ term:"Rapport P/F", fullName:"Rapport PaO₂/FiO₂ — Index d'oxygénation", def:"Indicateur de sévérité de l'insuffisance respiratoire = PaO₂ (mmHg) ÷ FiO₂ (de 0.21 à 1). Normal > 400 mmHg. Critère diagnostique et de gravité du SDRA (Berlin 2012).", expert:"SDRA léger : P/F 200-300 sous PEEP ≥ 5. SDRA modéré : P/F 100-200. SDRA sévère : P/F < 100 → décubitus ventral 16H + curarisation 48H. Calculateur intégré dans PulseUnit (🧮 Calculateurs). Toujours mesurer sous les mêmes conditions de PEEP pour comparaisons valides. Faussé par shunts intracardiaques.", cat:"VENTILATION"},
{ term:"Ballonnet", fullName:"Cuff de la sonde d’intubation", def:"Manchon gonflable entourant la sonde d’intubation, assurant l’étanchéité trachéale et prévenant les inhalations.", expert:"Pression cible : 20-30 cmH2O. Contrôle toutes les 8H au manomètre. Trop haute = nécrose trachéale. Trop basse = microinhalations -> pneumopathie acquise sous ventilation (PAVM).", cat:"VENTILATION"},
{ term:"Décubitus ventral", fullName:"Prone positioning", def:"Retournement du patient à 180° pour améliorer l’oxygénation dans le SDRA sévère. Durée recommandée : 16 heures consécutives minimum.", expert:"Mobilisation d’au moins 5 personnes. Vérifier avant : fixations IOT, CVC, cathéters. Protéger les points d’appui. Risque d’extubation accidentelle. Efficacité prouvée sur la mortalité.", cat:"VENTILATION"},
/* ===== VOIES ===== */
{ term:"VVP", fullName:"Voie Veineuse Périphérique", def:"Cathéter court (14G à 22G) inséré dans une veine périphérique. Première voie d’abord en urgence.", expert:"Surveiller : douleur, rougeur, oedème (phlébite). Changer toutes les 72-96H. Ne pas administrer de catécholamines ni de Nicardipine par VVP.", cat:"VOIES"},
{ term:"CVC", fullName:"Cathéter Veineux Central", def:"Cathéter long inséré en veine profonde (jugulaire interne, sous-clavière, fémorale) permettant la mesure de la PVC, des perfusions multiples et des drogues vasoactives.", expert:"Asepsie chirurgicale stricte à la pose et pour les soins. Pansement selon protocole. Radiographie thoracique systématique après pose jugulaire/sous-clavière.", cat:"VOIES"},
{ term:"KT artériel", fullName:"Cathéter artériel", def:"Cathéter inséré en artère radiale (ou fémorale) relié à un capteur pour mesure continue de la PA et prélèvements artériels (GDS).", expert:"Purge continue par NaCl 0.9% pressurisé à 300 mmHg. Surveiller l’aspect de la main en aval (coloration, chaleur). Rincer après chaque prélèvement. Zéro quotidien.", cat:"VOIES"},
{ term:"PICC", fullName:"Peripherally Inserted Central Catheter", def:"Cathéter central inséré par voie veineuse périphérique (veine basilique ou céphalique), dont l’extrémité se positionne en veine cave supérieure.", expert:"Indication : antibiothérapie prolongée, nutrition parentérale. Vérification radiologique systématique. Entretien identique au CVC.", cat:"VOIES"},
{ term:"KT dialyse", fullName:"Cathéter de dialyse (Shaldon)", def:"Cathéter double lumière de gros calibre (11-12F) inséré en veine profonde pour l’épuration extrarénale (CVVH, hémodialyse).", expert:"Débits requis : 150-300 mL/min. Verrous héparine après chaque séance. Risque infectieux élevé : asepsie stricte.", cat:"VOIES"},
{ term:"Chambre implantable", fullName:"Port-à-Cath (PAC)", def:"Dispositif sous-cutané relié à un cathéter central. Accès uniquement avec aiguille de Huber. Utilisé en oncologie et nutrition parentérale longue durée.", expert:"Accès exclusif avec aiguille de Huber. Purge et vérification du retour veineux avant chaque utilisation. Ne jamais forcer. Pansement occlusif autour de l’aiguille.", cat:"VOIES"},
/* ===== MATÉRIEL ===== */
{ term:"PSE", fullName:"Pousse-Seringue Électrique", def:"Dispositif motorisé poussant le piston d’une seringue à débit précis et constant. Indispensable pour les drogues vasoactives, la sédation et l’analgésie.", expert:"Vérifier : débit programmé, seringue chargée correctement, alarme occlusion active. Changer la seringue avec continuité (relais) pour les drogues vitales. Ne jamais laisser à 0 mL sur catécholamines.", cat:"MATÉRIEL"},
{ term:"Pompe volumétrique", fullName:"Perfuseur électronique à débit contrôlé", def:"Dispositif régulant le débit d’une poche de perfusion (NaCl, glucose, nutrition parentérale) avec alarmes d’occlusion et d’air.", expert:"Adapté aux grands volumes et débits élevés. Vérifier la ligne de perfusion, l’absence de kink, les alarmes. Préférer au PSE pour les solutés de grand volume.", cat:"MATÉRIEL"},
{ term:"ARTIS", fullName:"Générateur de dialyse continue (CVVH)", def:"Machine assurant l’épuration extrarénale continue par hémofiltration (CVVH) ou hémodialyse continue (CVVHD).", expert:"Surveiller : pressions du circuit, alarmes de clottage, bilan de substitution, débit anticoagulant (héparine ou citrate). Traçabilité horaire obligatoire.", cat:"MATÉRIEL"},
{ term:"Humidificateur", fullName:"Chambre d’humidification active", def:"Dispositif chauffant et humidifiant les gaz inspirés du respirateur pour prévenir l’assèchement des muqueuses et l’épaississement des sécrétions.", expert:"Vérifier quotidiennement le niveau d’eau distillée stérile. Surveiller la condensation dans le circuit (vidanger côté patient). Ne jamais laisser l’eau remonter vers le patient.", cat:"MATÉRIEL"},
{ term:"Filtre HME", fullName:"Heat and Moisture Exchanger (nez artificiel)", def:"Filtre hygroscopique placé entre la sonde d’intubation et le circuit du respirateur, assurant l’humidification passive des gaz inspirés.", expert:"Alternative à l’humidificateur active. Changer toutes les 24H ou si souillé. Ne pas combiner avec un humidificateur actif (incompatibles).", cat:"MATÉRIEL"},
{ term:"Vérif chambre", fullName:"Vérification de chambre — check-list de prise en charge", def:"Ensemble de 10 points de vérification systématique à réaliser lors de la prise en charge d'un patient en réanimation : tiroir ventilation, BAVU, alarmes scope, câbles, aspiration, O2, zéro KT artériel, pression ballonnet, humidificateur, alarme respirateur.", expert:"La vérification chambre est tracée par garde dans PulseUnit (barre de progression par lit). Inspirée des check-lists aéronautiques adaptées au secteur médical. Réduit les événements indésirables liés à des oublis d'équipement ou de réglage.", cat:"MATÉRIEL"},
{ term:"TOF", fullName:"Train-Of-Four (neurostimulation)", def:"Technique de monitorage de la curarisation par stimulation du nerf ulnaire et comptage des réponses musculaires (0 à 4 twitch).", expert:"TOF 0/4 = curarisation profonde. TOF 1-2/4 = niveau souhaité pour SDRA sévère. TOF 4/4 = récupération complète. Contrôle toutes les 2-4H si curare en continu.", cat:"MATÉRIEL"},
{ term:"Thermogard", fullName:"Système Thermogard — Contrôle de température interne", def:"Dispositif de thermorégulation invasive utilisant un cathéter intravasculaire à ballonnets parcouru par un liquide thermorégulé. Permet l'induction, le maintien et le réchauffement actif de la température corporelle cible.", expert:"Indications : hypothermie thérapeutique post-ACR (cible 33-36°C), hyperthermie réfractaire. Cathéter positionné en veine fémorale ou jugulaire. Protocole dédié dans PulseUnit (📋 Protocoles). Surveiller : diurèse, ionogramme (hypokaliémie lors du réchauffement), coagulation (risque hémorragique à basse T°), frissons (traitement Buspirone + Magnésium + Tramadol selon protocole).", cat:"MATÉRIEL"},
/* ===== HÉMODYNAMIQUE ===== */
{ term:"PAS / PAD", fullName:"Pression Artérielle Systolique et Diastolique", def:"PAS = pression maximale lors de la systole. PAD = pression minimale lors de la diastole. Normes adulte : PAS 110-140 mmHg / PAD 60-90 mmHg. Mesure par brassard (non invasive) ou KT artériel (invasive).", expert:"HTA sévère : PAS > 180 ou PAD > 110 → urgence tensionnelle si atteinte d'organe (AVC, OAP, dissection aortique). Hypotension : PAS < 90 → évaluer la PAM (cible ≥ 65 mmHg). Pression pulsée (PP = PAS - PAD) normale : 30-50 mmHg. PP élargie = insuffisance aortique ou HTAP. PP pincée < 25 mmHg = choc cardiogénique ou péricardite constrictive.", cat:"HÉMODYNAMIQUE"},
{ term:"PAM", fullName:"Pression Artérielle Moyenne", def:"Pression de perfusion des organes. PAM = (PAS + 2xPAD) / 3. Valeur normale : 70-100 mmHg. Objectif en choc septique : >= 65 mmHg.", expert:"PAM < 65 mmHg = hypoperfusion organique imminente. Première mesure : remplissage vasculaire. Si persistante -> catécholamines (Noradrénaline en 1ère intention). Objectif adapté si ATCD HTA.", cat:"HÉMODYNAMIQUE"},
{ term:"ECMO", fullName:"Extra-Corporeal Membrane Oxygenation", def:"Assistance circulatoire et/ou respiratoire extracorporelle. ECMO-VV = support pulmonaire. ECMO-VA = support cardio-pulmonaire.", expert:"Surveillance horaire : débit, oxygénation de la membrane, anticoagulation (TCA 60-80s), sites d’insertion. Contre-indication relative : coagulopathie sévère.", cat:"HÉMODYNAMIQUE"},
{ term:"Défibrillateur", fullName:"Défibrillateur - DSA - Pace-maker externe", def:"Appareil permettant de délivrer un choc électrique pour traiter les arythmies graves (FV, TV sans pouls) ou assurer une stimulation cardiaque externe.", expert:"Vérification quotidienne obligatoire (batterie, électrodes, décharge test). En ACR : choc le plus précoce possible. Énergie : 150-200J biphasique pour FV.", cat:"HÉMODYNAMIQUE"},
{ term:"DC / IC", fullName:"Débit Cardiaque / Index Cardiaque", def:"DC = volume éjecté par le coeur par minute (L/min). Normale : 4-8 L/min. IC = DC / surface corporelle (2.5-4 L/min/m²).", expert:"IC < 2.2 = bas débit cardiaque -> inotropes (Dobutamine). L’ITV à l’échographie est une mesure simple et répétable. Guider par PiCCO ou écho.", cat:"HÉMODYNAMIQUE"},
{ term:"RVS", fullName:"Résistances Vasculaires Systémiques", def:"Résistance que le ventricule gauche doit vaincre pour éjecter le sang. Élevées dans le choc cardiogénique, basses dans le choc septique.", expert:"RVS basses + DC élevé = choc distributif (septique). RVS élevées + DC bas = choc cardiogénique -> inotropes et vasodilatateurs. Guide la stratégie thérapeutique.", cat:"HÉMODYNAMIQUE"},
{ term:"Delta PP", fullName:"Variation de la pression pulsée", def:"Variation de la pression pulsée (PAS-PAD) entre inspiration et expiration en mode contrôlé. Delta PP > 13% = patient répondeur au remplissage.", expert:"Ne fonctionne qu’en mode contrôlé, rythme sinusal, VT >= 7 ml/kg. Alternative : lever passif de jambe (LPJ). Évite les remplissages inutiles.", cat:"HÉMODYNAMIQUE"},
{ term:"Choc cardiogénique", fullName:"Choc cardiogénique", def:"État de choc lié à une défaillance primitive du coeur entraînant un bas débit. PA effondrée, signes congestifs, extrémités froides, oligurie.", expert:"Cause principale : SCA avec dysfonction VG. Traitement : Dobutamine +/- Noradrénaline. Éviter le remplissage excessif. Écho cardiaque urgente. Risque ECMO-VA si réfractaire.", cat:"HÉMODYNAMIQUE"},
{ term:"Remplissage", fullName:"Fluid challenge - Expansion volémique", def:"Administration rapide d’un cristalloïde (250-500 mL NaCl 0.9% ou Ringer en 20 min) pour tester la réponse hémodynamique.", expert:"Évaluer la réponse : PAM >= +10% ou DC +15% = répondeur. Absence de réponse = stopper. Éviter le remplissage répété non guidé (surcharge -> EVLWI élevé, OAP).", cat:"HÉMODYNAMIQUE"},
/* ===== BIO ===== */
{ term:"GDS", fullName:"Gaz du Sang artériels", def:"Analyse du sang artériel mesurant pH, PaO2, PaCO2, bicarbonates, base excess, lactates et hémoglobine.", expert:"Valeurs normales : pH 7.35-7.45 / PaO2 80-100 mmHg / PaCO2 35-45 mmHg / HCO3- 22-26 mmol/L. Indispensable pour ajuster ventilation et traitement de l’équilibre acido-basique.", cat:"BIO"},
{ term:"Base Excess (BE)", fullName:"Excès de base — Paramètre acido-basique des GDS", def:"Mesure la quantité de base (mmol/L) nécessaire pour ramener le pH à 7.40 à PaCO₂ = 40 mmHg et T° = 37°C. Valeur normale : -2 à +2 mmol/L.", expert:"BE négatif (déficit en bases) = acidose métabolique : sepsis, acidose lactique, IRA, intoxication, diarrhée. BE positif = alcalose métabolique : vomissements, aspirations gastriques, diurétiques, hypokaliémie. Le BE isole la composante métabolique indépendamment de la ventilation — plus fiable que le seul HCO₃⁻ pour guider la correction. Toujours interpréter avec pH, PaCO₂, HCO₃⁻ et lactates.", cat:"BIO"},
{ term:"Lactates", fullName:"Lactatémie - Marqueur d’hypoperfusion", def:"Produit du métabolisme anaérobie en cas d’hypoxie tissulaire. Normale < 2 mmol/L. Choc si > 4 mmol/L.", expert:"Clearing des lactates > 10% en 6H = bon pronostic. Dosage toutes les 2-6H en choc. Causes : choc, ischémie mésentérique, intoxication CO ou metformine.", cat:"BIO"},
{ term:"NFS", fullName:"Numération Formule Sanguine", def:"Hémogramme complet : globules rouges, hémoglobine, hématocrite, globules blancs avec formule différentielle, plaquettes.", expert:"Hb cible en réa : 7-9 g/dL (seuil transfusionnel selon contexte). GB > 15 000 ou < 4 000 = syndrome inflammatoire. Thrombopénie < 50 000 = risque hémorragique. Analyse quotidienne.", cat:"BIO"},
{ term:"Coagulation", fullName:"TP - INR - TCA - Bilan d’hémostase", def:"TP (normale > 70%) / INR (normale 1) mesurent la voie extrinsèque. TCA mesure la voie intrinsèque (normale 26-36 sec). Reflètent la capacité de coagulation.", expert:"TP < 50% + TCA allongé = coagulopathie (CIVD, IHC, anticoagulants). INR > 1.5 = risque hémorragique péri-procédural. Évaluation avant tout geste invasif.", cat:"BIO"},
{ term:"Fibrinogène", fullName:"Fibrinogène plasmatique", def:"Protéine de coagulation synthétisée par le foie. Normale : 2-4 g/L. Diminue en CIVD ou hémodilution.", expert:"Fibrinogène < 1.5 g/L = risque hémorragique majeur -> Clottafact ou PFC. Augmenté en syndrome inflammatoire. Suivi obligatoire en CIVD.", cat:"BIO"},
{ term:"Ionogramme", fullName:"Ionogramme sanguin", def:"Bilan des électrolytes : Sodium (Na+), Potassium (K+), Chlore (Cl-), Bicarbonates (HCO3-).", expert:"Na+ 136-145 / K+ 3.5-5.0 mmol/L. Hyponatrémie < 130 = risque oedème cérébral. Hyperkaliémie > 6.5 = ECG urgent + traitement. Trou anionique élevé > 12 = intoxication, acidocétose.", cat:"BIO"},
{ term:"Créatinine / DFG", fullName:"Créatinine et Débit de Filtration Glomérulaire", def:"Créatinine = déchet azoté reflétant la fonction rénale. DFG normal > 90 mL/min/1.73m². Augmentation = insuffisance rénale.", expert:"Créatinine > 200 µmol/L = IRA sévère. IRA stade 3 (KDIGO) = indication potentielle CVVH. Adapter les posologies des médicaments à élimination rénale.", cat:"BIO"},
{ term:"AKI / IRA", fullName:"Acute Kidney Injury — Insuffisance Rénale Aiguë (stades KDIGO)", def:"Défaillance rénale aiguë classée en 3 stades selon les critères KDIGO, basés sur l'élévation de créatinine et/ou la diminution de diurèse.", expert:"Stade 1 : créatinine ×1.5-1.9 ou diurèse < 0.5 mL/kg/h pendant 6-12H. Stade 2 : créatinine ×2-2.9 ou diurèse < 0.5 mL/kg/h pendant ≥ 12H. Stade 3 : créatinine ×3 ou créatinine > 353 µmol/L ou diurèse < 0.3 mL/kg/h pendant ≥ 24H ou anurie ≥ 12H. Stade 3 = indication potentielle de CVVH. Causes à chercher systématiquement : hypovolémie (fonctionnelle), néphrotoxiques, obstruction, ischémie. Surveiller FEna, ionogramme, diurèse horaire.", cat:"BIO"},
{ term:"CRP", fullName:"Protéine C-Réactive", def:"Protéine de l’inflammation aiguë synthétisée par le foie. Augmente en 6-12H. Normale < 5 mg/L.", expert:"CRP > 100 mg/L = infection ou inflammation sévère. Utile pour suivre l’évolution sous antibiothérapie (devrait baisser à J3-J4). Peu spécifique (traumatisme, chirurgie).", cat:"BIO"},
{ term:"PCT", fullName:"Procalcitonine", def:"Biomarqueur plus spécifique de l’infection bactérienne que la CRP. Normale < 0.5 ng/mL. Élévation rapide en 2-4H après début de sepsis.", expert:"PCT > 2 ng/mL = forte probabilité de sepsis bactérien. > 10 ng/mL = choc septique. Guide la durée d’antibiothérapie (baisse > 80% = arrêt envisageable).", cat:"BIO"},
{ term:"Troponine", fullName:"Troponine I ou T ultrasensible", def:"Biomarqueur de nécrose myocardique. Dosage sériel à H0-H1/H3 pour diagnostic d’infarctus.", expert:"Augmentation isolée possible en réa sans SCA : sepsis, EP massive, IR, choc. Interpréter avec ECG et échographie. Corrélée à la gravité en sepsis.", cat:"BIO"},
{ term:"BNP / NT-proBNP", fullName:"Peptide Natriurétique Cérébral", def:"Hormone sécrétée par le ventricule en cas de distension pariétale. Biomarqueur de surcharge volumique et d’insuffisance cardiaque.", expert:"BNP > 400 pg/mL = forte probabilité de décompensation cardiaque. Utile pour distinguer OAP cardiogénique d’une détresse respiratoire non cardiaque.", cat:"BIO"},
{ term:"Hémocultures", fullName:"Hémocultures - Bactériémie", def:"Prélèvement de sang en conditions stériles (2-3 paires en 30 min) pour identifier une bactériémie ou une fongémie. À réaliser avant tout antibiotique.", expert:"2 paires (aérobie + anaérobie) en deux sites différents. Indication : température > 38.5°C ou < 36°C. Adapter l’ATB selon l’antibiogramme à réception.", cat:"BIO"},
{ term:"ECBU", fullName:"Examen Cytobactériologique des Urines", def:"Analyse des urines permettant de diagnostiquer une infection urinaire. Recherche bactéries, leucocyturie et nitrites.", expert:"Leucocyturie > 10/mm3 + bactériurie > 103 UFC/mL = infection urinaire. En réa : souvent colonisation de sonde. Traiter uniquement si sepsis + ECBU positif. Changer la sonde avant le prélèvement.", cat:"BIO"},
{ term:"FEna", fullName:"Fraction d'Excrétion du Sodium", def:"Calcul permettant de distinguer l'IRA fonctionnelle de l'IRA organique. FEna = (Na urinaire × créatinine plasmatique) / (Na plasmatique × créatinine urinaire) × 100.", expert:"FEna < 1% = IRA fonctionnelle (rein avide de sodium : déshydratation, bas débit cardiaque, syndrome hépato-rénal) → remplissage ou correction de la cause. FEna > 2% = IRA organique (nécrose tubulaire aiguë). Faussée par les diurétiques → utiliser alors la FEurée (< 35% = fonctionnelle). Valide uniquement en l'absence de diurétiques récents.", cat:"BIO"},
/* ===== SEPSIS ===== */
{ term:"Sepsis", fullName:"Sepsis - Dysfonction d’organe infectieuse", def:"Réponse dysrégulée de l’organisme à une infection entraînant une dysfonction d’organe (SOFA >= 2 points). Urgence vitale.", expert:"Bundle Sepsis 1H : hémocultures, lactates, antibiotiques, remplissage 30 mL/kg si PAM < 65, vasopresseurs si nécessaire. Chaque heure de retard à l’antibiothérapie augmente la mortalité.", cat:"SEPSIS"},
{ term:"Choc septique", fullName:"Choc septique - Vasoplégie septique", def:"Forme la plus grave du sepsis avec vasoplégie réfractaire nécessitant des vasopresseurs pour PAM >= 65 mmHg et lactates > 2 mmol/L.", expert:"Mortalité 40-50%. Noradrénaline = vasopresseur de 1ère intention. Adrénaline ou Vasopressine en 2e ligne. Hydrocortisone si choc réfractaire (Nora > 0.25 µg/kg/min). Contrôle source infectieuse urgent.", cat:"SEPSIS"},
{ term:"BMR", fullName:"Bactérie Multi-Résistante", def:"Bactérie ayant acquis une résistance à plusieurs classes d’antibiotiques, rendant les infections difficiles à traiter.", expert:"Principaux BMR : SARM, EBLSE, KPC. Dépistage à l’admission (patients EHPAD, rapatriements). Précautions contact systématiques. Signalement à l’équipe opérationnelle d’hygiène (EOH).", cat:"SEPSIS"},
{ term:"SARM", fullName:"Staphylocoque Aureus Résistant à la Méticilline", def:"Staphylocoque doré résistant aux bêta-lactamines. BMR fréquente en milieu hospitalier, responsable d’infections graves.", expert:"Traitement de référence : Vancomycine IV. Dépistage nasal. Isolement contact : sur-blouse et gants. Décolonisation possible (Mupirocine nasal + chlorhexidine) selon protocole.", cat:"SEPSIS"},
{ term:"BLSE", fullName:"Bêta-Lactamase à Spectre Étendu", def:"Enzymes produites par certaines entérobactéries (Klebsiella, E. coli) rendant inefficaces la majorité des pénicillines et céphalosporines.", expert:"Traitement : carbapénèmes (Méropénème). Précautions contact strictes. Dépistage rectal à l’admission pour patients à risque (EHPAD, hospitalisation récente).", cat:"SEPSIS"},
{ term:"ERV", fullName:"Entérocoque Résistant à la Vancomycine", def:"Entérocoque ayant acquis une résistance à la Vancomycine. Émergence préoccupante, peu d’options thérapeutiques.", expert:"Traitement : Linézolide ou Daptomycine. Isolement géographique strict. Signalement obligatoire à l’ARS. Décontamination de l’environnement.", cat:"SEPSIS"},
{ term:"Isolement contact", fullName:"Précautions Complémentaires Contact (PCC)", def:"Mesures additionnelles aux précautions standard pour limiter la transmission des BMR et pathogènes à transmission manuportée.", expert:"Gants et sur-blouse à l’entrée de la chambre. Matériel dédié au patient. SHA systématique. Chambre individuelle si possible. Signalisation sur la porte.", cat:"SEPSIS"},
{ term:"Antibiogramme", fullName:"Antibiogramme - Sensibilité aux antibiotiques", def:"Test de laboratoire déterminant la sensibilité d’un germe isolé aux différents antibiotiques. Résultat en 24-72H.", expert:"S = sensible, I = intermédiaire (dose-dépendant), R = résistant. Adapter l’antibiothérapie empirique dès réception (désescalade). Ne pas prescrire un ATB R en monothérapie.", cat:"SEPSIS"},
/* ===== ÉLIMINATION ===== */
{ term:"Sonde U", fullName:"Sonde urinaire à demeure (SAD)", def:"Sonde à ballonnet introduite dans la vessie pour drainer les urines en continu et mesurer la diurèse horaire.", expert:"Diurèse horaire < 0.5 mL/kg/h pendant 6H = oligurie -> signaler. Surveiller la couleur, l’aspect. Soin de méat quotidien. Retirer dès que possible (risque IUAS).", cat:"ÉLIMINATION"},
{ term:"SNG", fullName:"Sonde nasogastrique", def:"Sonde introduite par le nez jusqu’à l’estomac pour la nutrition entérale, l’aspiration digestive ou l’administration de médicaments.", expert:"Vérifier la position avant chaque utilisation (aspiration pH < 5, RX si doute). Contrôler le résidu gastrique toutes les 4-6H. Rincer avant et après administration.", cat:"ÉLIMINATION"},
{ term:"CVVH", fullName:"Hémofiltration Veino-Veineuse Continue", def:"Technique d’épuration extrarénale continue éliminant l’excès d’eau, les déchets azotés et les toxines urémiques. Indiquée dans l’IRA sévère.", expert:"Surveillance horaire : bilan de substitution, pressions circuit, débit anticoagulant. Risque de clottage (surveiller la pression transmembranaire). Vérifier l’équilibre hydroélectrolytique toutes les 4-6H.", cat:"ÉLIMINATION"},
{ term:"Stomie", fullName:"Stomie digestive ou urinaire", def:"Abouchement chirurgical d’un organe creux (intestin, uretère) à la peau pour assurer l’élimination en cas d’obstacle ou d’intervention.", expert:"Surveiller la couleur du stomate (rouge vif normal, foncé/noir = ischémie -> urgence chirurgicale). Mesurer les pertes (hydriques et électrolytiques). Appareillage adapté.", cat:"ÉLIMINATION"},
/* ===== MÉDICAMENTS ===== */
{ term:"Vasoactifs", fullName:"Catécholamines - Agents vasoactifs", def:"Famille de médicaments modifiant le tonus vasculaire et/ou la contractilité cardiaque. Indispensables dans les états de choc.", expert:"Administration exclusive sur voie centrale. Surveillance PA continue idéalement invasive. Ne jamais interrompre brutalement. Relais seringue à seringue pour les drogues vitales.", cat:"MÉDICAMENTS"},
{ term:"Sédation", fullName:"Sédation en réanimation", def:"Association d’hypnotiques et d’analgésiques pour assurer le confort, la tolérance au ventilateur et prévenir les traumatismes.", expert:"Concept Analgesia First : traiter la douleur avant la sédation. Objectif RASS -1 à 0 sauf indication spécifique. Sevrage progressif. Éviter la sédation profonde prolongée (délire, faiblesse, SSPT).", cat:"MÉDICAMENTS"},
{ term:"Curares", fullName:"Bloqueurs neuromusculaires", def:"Médicaments induisant une paralysie musculaire temporaire par blocage de la jonction neuromusculaire.", expert:"Toujours associés à une sédation profonde vérifiée. Monitoring TOF. Indications : SDRA sévère, tétanos, intubation difficile. Risque de myopathie si prolongé.", cat:"MÉDICAMENTS"},
{ term:"Adrénaline", fullName:"Adrénaline 1mg/ml", def:"Catécholamine d’urgence, vasopresseur et inotrope puissant (action α et β). Première intention dans l’ACR et l’anaphylaxie sévère.", expert:"PSE : 1mg/ml. Voie centrale impérative en continu. Surveillance scope et PA continue. Risque de nécrose cutanée si extravasation. En ACR : 1mg IVD toutes les 3-5 min.", cat:"MÉDICAMENTS"},
{ term:"Noradrénaline", fullName:"Noradrénaline diluée à 1mg/ml", def:"Catécholamine vasopressive de référence dans le choc septique et vasoplégique. Action α-adrénergique prépondérante.", expert:"PSE : 1mg/ml. Conservation 24H. Voie centrale obligatoire. PA invasive recommandée. Extravasation = nécrose cutanée -> antidote local phentolamine. Ne jamais interrompre brutalement.", cat:"MÉDICAMENTS"},
{ term:"Dobutamine", fullName:"Dobutamine diluée à 5mg/ml", def:"Catécholamine inotrope positive (β1) dans l’insuffisance cardiaque aiguë à bas débit. Augmente la contractilité sans vasopression marquée.", expert:"PSE : 5mg/ml. Voie centrale recommandée. Surveillance ECG continue (arythmogène). Associée à la Noradrénaline si bas débit + vasoplégie.", cat:"MÉDICAMENTS"},
{ term:"Sufentanil", fullName:"Sufentanil dilué à 10µg/ml", def:"Opioïde de synthèse 5-10x plus puissant que la morphine. Utilisé en analgésie et sédation-analgésie en réanimation.", expert:"PSE : 10µg/ml. Conservation 24H. Surveillance respiratoire stricte. Adaptation selon CPOT/BPS. Antidote Naloxone. Accumulation possible en IR/IH.", cat:"MÉDICAMENTS"},
{ term:"Midazolam", fullName:"Midazolam dilué à 1mg/ml", def:"Benzodiazépine à action rapide utilisée en sédation, anxiolyse, épilepsie et induction anesthésique.", expert:"PSE : 1mg/ml. Conservation 24H. Adaptation selon RASS. Accumulation en IH/IR. Antidote : Flumazénil. Risque de dépendance si prolongé.", cat:"MÉDICAMENTS"},
{ term:"Propofol", fullName:"Propofol 10mg/ml", def:"Hypnotique intraveineux à action et réveil rapides. Sédation procédurale et maintien sous ventilation mécanique.", expert:"PSE : 10mg/ml. Conservation 12H (émulsion lipidique). PRIS (syndrome de perfusion) si > 4mg/kg/h prolongé (acidose, arythmies, myoglobinurie). Surveiller triglycérides et CPK.", cat:"MÉDICAMENTS"},
{ term:"Furosémide", fullName:"Furosémide 10mg/ml", def:"Diurétique de l’anse agissant sur l’anse de Henle. Utilisé dans les surcharges hydrosodées, l’oligurie et l’OAP.", expert:"PSE : 10mg/ml. Conservation 24H. Photosensible. Surveiller kaliémie (hypokaliémie fréquente), natrémie, diurèse horaire. Hypovolémie si doses excessives.", cat:"MÉDICAMENTS"},
{ term:"Héparine", fullName:"Héparine sodique 20000UI/48ml", def:"Anticoagulant parentéral activant l’antithrombine III. Utilisé en thromboprophylaxie, traitement thromboembolique et pour les circuits extracorporels.", expert:"PSE : 20000UI/48ml (≈416 UI/ml). Surveillance TCA (cible 60-80s) ou anti-Xa toutes les 6H. Risque TIH (thrombopénie induite). Antidote : Protamine sulfate.", cat:"MÉDICAMENTS"},
{ term:"Citrate", fullName:"Anticoagulation régionale au citrate — CVVH/CVVHD", def:"Anticoagulant utilisé dans les circuits d’épuration extrarénale (CVVH/CVVHD). Le citrate chélate le calcium ionisé dans le circuit, créant une anticoagulation locale. Il est ensuite métabolisé par le foie en bicarbonate.", expert:"Avantages vs héparine : risque hémorragique réduit, pas de TIH. Surveillance indispensable : calcium ionisé post-filtre (cible < 0.4 mmol/L) et systémique (cible 1.1-1.3 mmol/L) toutes les 4-6H. Signes de surdosage citrate (IHC) : acidose métabolique + hypocalcémie ionisée + rapport Ca total/Ca ionisé > 2.5. Contre-indication : insuffisance hépatique sévère (accumulation). Protocole de service obligatoire.", cat:"MÉDICAMENTS"},
{ term:"Nicardipine", fullName:"Nicardipine 1mg/ml - VVC UNIQUEMENT", def:"Inhibiteur calcique vasodilatateur artériel puissant. Traitement des HTA sévères et urgences hypertensives.", expert:"PSE : 1mg/ml. Conservation 24H. VOIE CENTRALE EXCLUSIVE (nécrose veineuse sur VVP). Surveillance PA continue. Photosensible : protéger la tubulure. Tachycardie réflexe possible.", cat:"MÉDICAMENTS"},
{ term:"Nefopam", fullName:"Nefopam dilué à 2.5mg/ml", def:"Antalgique central non opioïde inhibant la recapture des monoamines. Utilisé en analgésie multimodale (épargne morphinique).", expert:"PSE : 2.5mg/ml. Conservation 24H. Surveiller tachycardie et convulsions. Contre-indiqué : épilepsie, glaucome, trouble urinaire obstructif.", cat:"MÉDICAMENTS"},
{ term:"Risordan", fullName:"Risordan (Isosorbide dinitrate) 1mg/ml", def:"Dérivé nitré vasodilatateur veineux et artériel. OAP hypertensif, insuffisance cardiaque aiguë, angor instable.", expert:"PSE : 1mg/ml. Conservation 24H. Surveillance PA stricte (hypotension brutale). Contre-indiqué avec les IPDE5 (Sildenafil). Photosensible, protéger la tubulure.", cat:"MÉDICAMENTS"},
{ term:"Salbutamol", fullName:"Salbutamol Fort 1mg/ml", def:"Bronchodilatateur β2-agoniste sélectif. Bronchospasmes sévères (asthme, BPCO) et traitement d’urgence de l’hyperkaliémie.", expert:"PSE : 1mg/ml. Conservation 24H. Surveiller tachycardie sinusale et hypokaliémie. Peut aggraver une ischémie myocardique.", cat:"MÉDICAMENTS"},
{ term:"Umuline", fullName:"Umuline Rapide diluée à 1UI/ml", def:"Insuline rapide humaine. Correction des hyperglycémies, protocoles d’insulinothérapie intensive et traitement de l’hyperkaliémie sévère.", expert:"PSE : 1UI/ml. Conservation 48H. Contrôle glycémique horaire si continu (cible 8-10 mmol/L en réa). Risque d’hypoglycémie : seuil d’alerte < 4 mmol/L.", cat:"MÉDICAMENTS"},
{ term:"Nimbex", fullName:"Cisatracurium (Nimbex) 5mg/ml", def:"Curare non dépolarisant à durée intermédiaire. Curarisation contrôlée dans le SDRA sévère (P/F < 150) et lors des gestes.", expert:"PSE : 5mg/ml. Conservation 24H AU RÉFRIGÉRATEUR. Sédation profonde (RASS -4/-5) obligatoire. Monitoring TOF. Hydrolyse de Hofmann : pas d’accumulation en IR/IH.", cat:"MÉDICAMENTS"},
{ term:"Morphine", fullName:"Morphine sulfate IV", def:"Opioïde de référence pour l’analgésie des douleurs sévères. Agoniste des récepteurs µ centraux et périphériques.", expert:"Titration : bolus 2-4 mg IVL, réévaluation à 15 min. Surveillance : FR, SpO2, RASS. Antidote : Naloxone 0.4 mg IVL. Accumulation en insuffisance rénale (métabolites actifs).", cat:"MÉDICAMENTS"},
{ term:"Kétamine", fullName:"Kétamine (Kétalar) - Anesthésique dissociatif", def:"Antagoniste NMDA aux propriétés analgésiques, bronchodilatatrices et stabilisatrices de l’hémodynamique. Utilisé en sédation procédurale et comme adjuvant.", expert:"Dose analgésique : 0.1-0.3 mg/kg IVL. Maintient la PA et la bronchomotricité. Peut provoquer des hallucinations -> associer une benzodiazépine si doses élevées. Utile dans l’asthme aigu grave.", cat:"MÉDICAMENTS"},
{ term:"Paracétamol IV", fullName:"Paracétamol (Perfalgan) 10mg/ml", def:"Antalgique et antipyrétique non opioïde de première intention. Analgésie multimodale avec épargne morphinique.", expert:"Dose adulte : 1g IV en 15 min, max 4g/24H (2g si poids < 50 kg ou IH). Conservation 24H après ouverture. Interactions : AVK (potentialisation), hépatotoxiques.", cat:"MÉDICAMENTS"},
{ term:"Amiodarone", fullName:"Amiodarone (Cordarone) - Antiarythmique", def:"Antiarythmique de classe III utilisé dans les TV, FA à fréquence rapide et la réanimation d’ACR réfractaire.", expert:"En ACR (FV réfractaire) : 300 mg IVD puis 150 mg. En FA rapide : 150-300 mg sur 30 min puis relais PSE. Voie centrale en continu (phlébite sur VVP). Demi-vie très longue (40-55 jours).", cat:"MÉDICAMENTS"},
{ term:"Atropine", fullName:"Atropine sulfate - Parasympatholytique", def:"Antagoniste muscarinique utilisé dans les bradycardies symptomatiques et comme antidote des organophosphorés.", expert:"Dose bradycardie : 0.5-1 mg IVD, max 3 mg. Effet en 1-2 min. En intoxication aux organophosphorés : doses massives répétées jusqu’à disparition des sécrétions.", cat:"MÉDICAMENTS"},
{ term:"Magnésium", fullName:"Sulfate de magnésium (MgSO4)", def:"Électrolyte aux propriétés antiarythmiques et neuroprotectrices. Torsade de pointe, éclampsie, hypomagnésémie, asthme sévère.", expert:"Dose torsade : 2g IV en 5 min. Dose asthme : 2g IV sur 20 min. Surveiller kaliémie (souvent associée à hypokaliémie). Surdosage : abolition des ROT, apnée -> Gluconate de calcium IV.", cat:"MÉDICAMENTS"},
{ term:"KCl", fullName:"Chlorure de potassium - Supplémentation", def:"Électrolyte corrigeant les hypokaliémies (< 3.5 mmol/L) fréquentes en réanimation (diurétiques, nutrition, aspirations).", expert:"JAMAIS en IVD (arrêt cardiaque). Toujours dilué sur voie centrale (max 40 mmol/500 mL, débit max 20 mmol/h). Contrôle ionogramme à H1 puis toutes les 4-6H.", cat:"MÉDICAMENTS"},
{ term:"Bicarbonate Na", fullName:"Bicarbonate de sodium 4.2% ou 8.4%", def:"Solution alcalinisante pour acidoses métaboliques sévères et hyperkaliémie menaçante.", expert:"4.2% = isotonique (VVP possible). 8.4% = hypertonique = VVC obligatoire. Indication : pH < 7.15 + acidose métabolique. Correction progressive pour éviter alcalose rebond.", cat:"MÉDICAMENTS"},
{ term:"Vasopressine", fullName:"Vasopressine - Hormone antidiurétique", def:"Hormone vasoconstrictrice directe (récepteurs V1). Utilisée en 2e ligne dans le choc septique réfractaire à la Noradrénaline.", expert:"PSE : 0.03-0.04 UI/min. Voie centrale. Épargne en Noradrénaline. Attention : ischémie mésentérique et coronarienne à doses élevées. Ne pas augmenter au-delà de 0.04 UI/min.", cat:"MÉDICAMENTS"},
{ term:"Albumine 20%", fullName:"Albumine humaine 20%", def:"Colloïde naturel utilisé pour le remplissage chez le patient hypo-albuminémique, la prévention du syndrome hépato-rénal et certains états de choc.", expert:"Corriger une albumine < 20 g/L associée à une instabilité hémodynamique. Dose usuelle : 100-200 mL IV sur 30-60 min. Conservation 24H après ouverture. Réserver aux indications validées.", cat:"MÉDICAMENTS"},
{ term:"Vancomycine", fullName:"Vancomycine - Glycopeptide anti-SARM", def:"Antibiotique glycopeptide actif sur les cocci Gram positif résistants, notamment le SARM.", expert:"Surveillance des dosages résiduels (cible 15-20 mg/L). Néphrotoxique et ototoxique, surveiller la créatinine quotidiennement. Ajustement posologique en IR.", cat:"MÉDICAMENTS"},
{ term:"Méropénème", fullName:"Méropénème - Carbapénème large spectre", def:"Antibiotique carbapénème à très large spectre, actif sur la plupart des bactéries Gram+ et Gram- (incluant BLSE) et anaérobies.", expert:"Antibiotique de recours pour les sepsis sévères à entérobactéries BLSE. Administré en perfusion prolongée (3-4H) pour optimiser le temps au-dessus de la CMI.", cat:"MÉDICAMENTS"},
{ term:"Naloxone", fullName:"Naloxone (Narcan) - Antidote opioïdes", def:"Antagoniste compétitif des récepteurs opioïdes. Antidote des surdosages en opiacés (dépression respiratoire, coma).", expert:"Dose : 0.4 mg IVL, renouvelable toutes les 2 min. Demi-vie courte (30-90 min) < celle des opioïdes -> risque de rechute sédative. Surveiller FR et SpO2 pendant 2-4H.", cat:"MÉDICAMENTS"},
{ term:"Flumazénil", fullName:"Flumazénil (Anexate) - Antidote benzodiazépines", def:"Antagoniste compétitif des récepteurs aux benzodiazépines. Antidote du surdosage en BZD (Midazolam, Diazépam).", expert:"Dose : 0.2 mg IVL, répété toutes les 60 sec, max 1 mg. Demi-vie < celle des BZD -> risque de resédation. Peut déclencher une crise d’épilepsie de sevrage.", cat:"MÉDICAMENTS"},
{ term:"Clexane", fullName:"Énoxaparine (Clexane) - HBPM", def:"Héparine de Bas Poids Moléculaire utilisée en prévention (0.4 mL/j SC) ou traitement (1 mg/kg x2/j SC) des maladies thromboemboliques.", expert:"Adapter en IR (surveillance anti-Xa si DFG < 30 mL/min). TIH plus rare qu’avec HNF. Injection SC stricte, ne pas frictionner. Antidote partiel : Protamine.", cat:"MÉDICAMENTS"},
{ term:"Oméprazole IV", fullName:"Oméprazole - Inhibiteur de la pompe à protons", def:"IPP inhibant la sécrétion acide gastrique. Prévention des ulcères de stress, hémorragies digestives hautes, oesophagites.", expert:"Indication prophylactique systématique en réanimation (ulcère de stress). Dose : 40 mg IV/j. Favorise les pneumopathies à germes digestifs si pH gastrique trop alcalin.", cat:"MÉDICAMENTS"},
{ term:"Protamine", fullName:"Protamine sulfate - Antidote héparine", def:"Antidote de l’héparine non fractionnée. Neutralise l’héparine en formant un complexe stable. En cas de surdosage ou de fin de CEC/ECMO.", expert:"1 mg de protamine neutralise 100 UI d’héparine. Injection lente (> 10 min) pour éviter les réactions anaphylactiques (hypotension, bronchospasme). Antidote partiel des HBPM.", cat:"MÉDICAMENTS"},

/* ===== PHARMA & CLINIQUE ===== */
{ term:"HGT", fullName:"Hyperglycaemia Test - Glycémie capillaire", def:"Mesure de la glycémie par prélèvement capillaire au bout du doigt (dextro). Valeur normale à jeun : 4-6 mmol/L (0.7-1.1 g/L). Résultat 'HI' = valeur trop élevée pour le lecteur (> 33 mmol/L).", expert:"En réa : objectif glycémique 6-10 mmol/L (insulinothérapie intensive si > 10). Surveillance 1H si perfusion d’insuline, 4-6H en dehors. Hypoglycémie < 4 mmol/L = urgence : resucrage IV (G30%). Mesurer les 2 mains si valeur aberrante.", cat:"BIO"},
{ term:"Hémocue", fullName:"Hémoglobinomètre Hémocue - Hb capillaire", def:"Dispositif de mesure rapide de l’hémoglobine par voie capillaire. Utilisé en urgence pour évaluer une anémie au lit du patient sans attendre le bilan complet.", expert:"Valeur normale Hb : Homme 13-17 g/dL / Femme 12-16 g/dL. En réa : seuil transfusionnel généralement 7 g/dL (8-9 si pathologie cardio). Résultat corrélé mais pas strictement identique à l’Hb veineuse. Confirmer par NFS si décision thérapeutique.", cat:"BIO"},
{ term:"Glycémie", fullName:"Glycémie — Taux de glucose sanguin", def:"Concentration de glucose dans le sang. Valeur normale à jeun : 0,7-1,1 g/L (3,9-6,1 mmol/L). En réanimation, la cible est 1,0-1,8 g/L selon les protocoles d'insulinothérapie.", expert:"Hypoglycémie < 0,7 g/L : urgence métabolique, resucrage IV immédiat (G30% 50 mL ou G10% en débit). Hyperglycémie > 1,8 g/L en réa : adapter le protocole insuline. Convertir en mmol/L : valeur g/L × 5,556. Surveillance horaire si IVSE insuline. Risque accru d'infections et de mortalité si hyperglycémie prolongée.", cat:"BIO"},
{ term:"Cétonémie", fullName:"Cétonémie ou Cétonurie capillaire (mg/dL)", def:"Mesure des corps cétoniques (bêta-hydroxybutyrate) dans le sang ou les urines. Témoin d’un catabolisme lipidique en l’absence d’apport glucidique ou dans l’acidocétose diabétique.", expert:"Cétonémie > 3 mmol/L = acidocétose sévère. Surveillance chez le patient diabétique ou à jeun prolongé. En réa : peut être élevée dans les états de jeûne, sepsis ou nutrition parentérale exclusive. Traitement : insuline + glucosé IV.", cat:"BIO"},
{ term:"Bandelette U", fullName:"Bandelette urinaire - Analyse physicochimique", def:"Test semi-quantitatif permettant d’analyser en quelques minutes les urines : glucose, corps cétoniques, sang, protéines, leucocytes, nitrites, densité, pH, bilirubine.", expert:"Lecture à 2 min pour la plupart des paramètres. Leucocytes + nitrites positifs = probable infection urinaire. Protéinurie +++ = insuffisance rénale ou néphropathie. Densité > 1.020 = urines concentrées (déshydratation). Résultats à corréler à l’ECBU si doute clinique.", cat:"BIO"},
{ term:"Waterlow", fullName:"Score de Waterlow - Risque escarre", def:"Score de risque d’escarre cotant 8 paramètres : sexe/masse corporelle, aspect cutané, mobilité, âge, continence, appétit, malnutrition tissulaire, déficiences neurologiques, chirurgie. Score total sur 45+.", expert:"0-9 : pas de risque / 10-14 : risque moyen / 15-19 : haut risque / 20+ : très haut risque. Supérieur au score de Norton car prend en compte plus de facteurs de risque. Déclenche la prescription d’un matelas et d’un protocole de prévention.", cat:"SCORES"},
{ term:"Score sevrage", fullName:"Score de sevrage alcoolique ou médicamenteux", def:"Outil d’évaluation de l’intensité du syndrome de sevrage (alcool, benzodiazépines, opiacés). Guide la stratégie de substitution et les doses thérapeutiques.", expert:"Différents scores selon la substance : CIWA-Ar (alcool), COWS (opiacés). Un score élevé = risque convulsif et de delirium tremens. Traitement préventif systématique si contexte d’addiction. Surveillance rapprochée dans les 24-72H suivant l’arrêt.", cat:"SCORES"},
{ term:"Somnolence", fullName:"Échelle de somnolence - Vigilance résiduelle", def:"Évaluation du niveau de vigilance et de somnolence résiduelle du patient. Utilisée lors du sevrage ventilatoire et de l’évaluation neurologique.", expert:"Distinguer : somnolence physiologique (post-sédation en cours de levée) vs pathologique (lésion cérébrale, intoxication, sepsis). Couplée au Glasgow et au RASS. Facteur-clé dans la décision d’extubation : patient doit être éveillable et répondant.", cat:"SCORES"},
{ term:"ALGOPLUS", fullName:"ALGOPLUS - Douleur sujet âgé non communicant", def:"Échelle comportementale d’hétéro-évaluation de la douleur aiguë chez la personne âgée ne pouvant communiquer. Cotation de 0 à 5. Seuil d’alerte : score >= 2/5.", expert:"5 items observés : visage, regard, plainte, position corporelle, comportements atypiques. Simple et rapide (< 1 min). Validée pour les gestes douloureux aigus. Adaptée aux patients déments ou confus. Complémentaire de l’ECPA pour la douleur chronique.", cat:"SCORES"},
{ term:"DOLOPLUS", fullName:"DOLOPLUS - Douleur chronique sujet âgé", def:"Échelle d’hétéro-évaluation de la douleur chronique chez la personne âgée non communicante. 10 items sur 3 dimensions (somatique, psychomotrice, psychosociale). Seuil : >= 5/30.", expert:"Évaluation sur 2-3 jours d’observation. Seuil pathologique >= 5/30. Différencie douleur aiguë et chronique. Adaptée aux maisons de retraite et soins palliatifs. Doit être cotée par des soignants connaissant le patient (comportement habituel de référence).", cat:"SCORES"},
{ term:"ECPA", fullName:"Échelle Comportementale pour Personnes Âgées", def:"Échelle d’hétéro-évaluation de la douleur en 8 items (avant et pendant les soins). Score de 0 à 32. Seuil d’alerte >= 6/32.", expert:"Évalue : expression du visage, position spontanée, mouvements, relation à autrui, anticipation anxieuse des soins, réactions pendant les mobilisations, réactions pendant les soins des zones douloureuses, plaintes verbales. Cotée avant et pendant les soins.", cat:"SCORES"},
{ term:"EVS", fullName:"Échelle Verbale Simple (douleur)", def:"Échelle verbale d’auto-évaluation de la douleur en 5 niveaux : absente, faible, modérée, intense, insupportable. Pour patient communicant.", expert:"Simple et rapide. Utilisée quand le patient ne peut pas utiliser l’ENS (confusion légère, personne âgée). Seuil de traitement : douleur modérée. Limites : moins sensible que l’ENS pour mesurer les variations.", cat:"SCORES"},
{ term:"P Crête", fullName:"Pression de crête - Pression de pointe inspiratoire", def:"Pression maximale atteinte dans les voies aériennes en fin d’insufflation sur le respirateur. Inclut les résistances des voies aériennes + la compliance pulmonaire.", expert:"Normale < 35 cmH2O. P Crête élevée mais Pplat normale = résistances augmentées (bouchon muqueux, bronchospasme, coudure sonde). P Crête ET Pplat élevées = compliance réduite (OAP, atélectasie, pneumothorax).", cat:"VENTILATION"},
{ term:"VMin", fullName:"Volume Minute (ventilation)", def:"Volume total d’air ventilé par minute = VT x Fréquence respiratoire. Valeur normale : 6-10 L/min. Affiché sur le respirateur (VMin inspiratoire et expiratoire).", expert:"VMin élevé = hyperventilation ou majoration du travail respiratoire. VMin bas = hypoventilation -> hypercapnie. En VS-AI : le VMin spontané du patient est un indicateur clé de la tolérance du sevrage ventilatoire.", cat:"VENTILATION"},
{ term:"NO", fullName:"Monoxyde d’azote inhalé (NO - en PPM)", def:"Gaz vasodilatateur pulmonaire sélectif administré par inhalation. Réduit les résistances vasculaires pulmonaires sans effet systémique. Utilisé dans les HTAP sévères et certains SDRA.", expert:"Dose habituelle : 5-20 ppm. Surveillance de la méthémoglobinémie. Arrêt progressif (rebond d’HTAP si arrêt brutal). Réservé aux formes sévères d’HTAP ou SDRA avec hypoxémie réfractaire. Dispositif dédié (AirNo ou INOmax).", cat:"VENTILATION"},
{ term:"Sédaconda", fullName:"Sédaconda - Isoflurane inhalé en réanimation", def:"Dispositif (AnaConDa) permettant d’administrer des anesthésiques volatils (Isoflurane) via le circuit du respirateur en réanimation. Alternative aux agents IV pour la sédation.", expert:"Avantages : réveil plus rapide, effet bronchodilatateur, protection organique. Surveillance Etiso (concentration expirée). Nécessite un filtre adsorbant spécifique (AnaConDa). Contre-indiqué dans : HTIC, FC instable, hyperthermie maligne.", cat:"VENTILATION"},
{ term:"ECBC", fullName:"Examen Cyto-Bactériologique des Crachats (ou aspirations bronchiques)", def:"Analyse microbiologique des sécrétions bronchiques pour identifier un germe responsable de pneumopathie (dont PAVM).", expert:"En réa : prélèvement par aspiration endotrachéale ou brosse protégée (LBA). Réaliser avant antibiothérapie si possible. Résultat en 24-48H. Adapter l’antibiothérapie selon l’antibiogramme (désescalade). BK tubage si suspicion de tuberculose.", cat:"VENTILATION"},
{ term:"Redon", fullName:"Drain de Redon - Drainage chirurgical aspiratif", def:"Drain souple à aspiration active placé en fin d’intervention chirurgicale pour évacuer les collections (hématomes, séromes, sécrétions). Système fermé stérile.", expert:"Aspect S = séreux (normal) / H = hématique (surveillance) / B = bilieux (intervention chirurgicale urgente). Mesurer les quantités toutes les 8H. Ablation quand le débit < 20-30 mL/24H selon prescription. Asepsie stricte lors des manipulations.", cat:"ÉLIMINATION"},
{ term:"Manovac", fullName:"Drain de Manovac - Drainage chirurgical passif", def:"Drain souple à aspiration passive (poire déprimable) utilisé en chirurgie abdominale et orthopédique. Moins fort que le Redon.", expert:"Même surveillance que Redon pour l’aspect et les quantités. Vider et comprimer régulièrement pour maintenir l’aspiration. Signaler tout arrêt d’aspiration ou écoulement important.", cat:"ÉLIMINATION"},
{ term:"Drain de Kehr", fullName:"Drain de Kehr - Drainage biliaire", def:"Drain en T placé dans le cholédoque après chirurgie biliaire pour drainer la bile et maintenir la perméabilité des voies biliaires.", expert:"Aspect normal : bile jaune-vert claire. Aspect trouble/sanglant = complication. Débit normal : 300-500 mL/j. Chute brutale = obstruction ou reflux intrahépatique. Ne jamais clammer sans prescription médicale. Bilan biliaire à surveiller.", cat:"ÉLIMINATION"},
{ term:"PCA", fullName:"Patient Controlled Analgesia - Analgésie contrôlée par le patient", def:"Système permettant au patient d’auto-administrer des bolus d’analgésique (morphine généralement) à la demande, dans des limites préréglées par le médecin.", expert:"Paramètres : dose du bolus, délai réfractaire, dose max sur 4H. Surveillance : sédation, FR, SpO2. Éduquer le patient sur l’utilisation. Ne pas appuyer pour le patient. Différent du PSE (débit continu). Utilisé en post-opératoire ou en soins palliatifs.", cat:"MÉDICAMENTS"},
{ term:"VAC", fullName:"Vacuum Assisted Closure - Thérapie par Pression Négative (TPN)", def:"Traitement des plaies complexes par application d’une pression négative continue ou intermittente via un pansement en mousse connecté à une pompe à vide.", expert:"Indiqué : plaies chroniques, escarres profondes, déhiscences de cicatrices, pieds diabétiques. Pression réglée selon prescription (souvent -125 mmHg). Changement de pansement tous les 2-3 jours. Surveiller : étanchéité du système, couleur et quantité des exsudats dans le réservoir.", cat:"MATÉRIEL"},
{ term:"Réflexe de toux", fullName:"Réflexe de toux - Test de déglutition / extubation", def:"Réflexe protecteur des voies aériennes évalué avant toute extubation ou décision de retrait de la sonde de trachéotomie. Indicateur de la capacité à protéger les VAS.", expert:"Présent = bon signe pour l’extubation. Absent = risque majeur de fausse route, d’inhalation et de réintubation. À évaluer systématiquement avec le Glasgow, le RASS et la déglutition. Absence = contre-indication relative à l’extubation (trachéotomie souvent préférée).", cat:"NEURO"},
{ term:"Score BPS complet", fullName:"Behavioral Pain Scale - Cotation détaillée", def:"Échelle BPS de 3 à 12 cotant : Expression du visage (1-4) + Tonus des membres supérieurs (1-4) + Adaptation au respirateur (1-4).", expert:"Expression visage : 1=détendu / 2=front plissé / 3=paupières crispées / 4=joues crispées. Membres : 1=aucun / 2=flexion partielle / 3=flexion complète avec doigts / 4=rétractation (opposition aux soins). Respirateur : 1=adapté / 2=lutte ponctuelle / 3=lutte contre / 4=non ventilable. Score >= 6 = douleur non contrôlée.", cat:"SCORES"},
{ term:"Glasgow complet", fullName:"Score de Glasgow - Cotation Y+V+M", def:"GCS = Ouverture des yeux (Y 1-4) + Réponse verbale (V 1-5) + Réponse motrice (M 1-6). Score total : 3 (coma profond) à 15 (patient normal).", expert:"Y : 4=spontanée / 3=à la demande / 2=à la douleur / 1=aucune. V : 5=orientée / 4=confuse / 3=inappropriée / 2=incompréhensible / 1=aucune. M : 6=obéit / 5=localise / 4=évitement inadapté / 3=flexion / 2=extension / 1=aucune. GCS <= 8 = intubation. Toujours noter Y+V+M séparément.", cat:"NEURO"},
{ term:"RASS complet", fullName:"Richmond Agitation Sedation Scale - Échelle complète", def:"Échelle de sédation de -5 à +4 : agitation (+4 à +1) / éveillé (0) / sédation légère à profonde (-1 à -5).", expert:"+4=combatif / +3=très agité (arrache cathéters) / +2=agité (mouvements fréquents) / +1=anxieux. 0=éveillé et calme. -1=somnolent (contact visuel > 10 sec) / -2=réveil bref (< 10 sec) / -3=bouge à l’appel / -4=immobile, réagit à douleur / -5=immobile à l’appel ET à la douleur. Cible habituelle : -1 à 0.", cat:"SCORES"},
{ term:"Pupilles", fullName:"Examen pupillaire bilatéral", def:"Évaluation séparée des pupilles droite et gauche : Mydriase (dilatation) / Myosis (constriction) / Intermédiaire / Réactive (au réflexe photo-moteur) / Aréactive.", expert:"Anisocorie (asymétrie) = urgence neuro. Mydriase bilatérale aréactive = engagement cérébral, intoxication. Myosis bilatéral serré = opiacés, lésion protubérantielle. Intermédiaire aréactive = mort encéphalique possible. À noter avec l’heure et le Glasgow.", cat:"NEURO"},

/* ===== ABRÉVIATIONS — A. MÉDICAMENTS (RD:PRO/SOIN/5-2/11) ===== */
{ term:"ADRE", fullName:"Adrenaline", def:"Catecholamine endogene alpha et beta-adrenergique. 1ere intention en ACR, anaphylaxie et vasopresseur de recours.", expert:"ACR : 1 mg IV toutes les 2 min. Anaphylaxie : 0.5 mg IM face anterolatérale cuisse. En continu : diluer dans NaCl, voie centrale. Surveiller FC, PA, extremites.", cat:"ABREV"},
{ term:"ALBU / Serum ALB", fullName:"Albumine", def:"Proteine plasmatique de remplissage vasculaire (4% ou 20%). Hypoalbuminemie severe ou remplissage.", expert:"Albumine 20% : hypoalbuminemie < 20 g/L. Ne pas utiliser en 1ere intention pour remplissage. Surveiller oedemes et bilan entrees-sorties.", cat:"ABREV"},
{ term:"AMK", fullName:"Amiklin (Amikacine)", def:"Aminoglycoside a large spectre actif sur les BGN dont Pseudomonas. Dose unique journaliere.", expert:"Dose : 15-20 mg/kg/j IV 30 min. Dosage residuel avant 3e injection. Ototoxicite et nephrotoxicite : surveiller creatinine et diurese.", cat:"ABREV"},
{ term:"B/A", fullName:"Bricanyl / Atrovent (Ipratropium / Terbutaline)", def:"Association bronchodilatatrice en aerosoltherapie.", expert:"Diluer dans NaCl 0.9%. Nebulisation 15-20 min. Surveiller FC (tachycardie) et tremblements.", cat:"ABREV"},
{ term:"B/P", fullName:"Bricanyl / Pulmicort (Terbutaline / Budesonide)", def:"Association bronchodilatatrice et corticoide inhale. BPCO, asthme.", expert:"Rincer la sonde apres Pulmicort pour eviter les depots. Efficace sur l'inflammation bronchique chronique.", cat:"ABREV"},
{ term:"B1B6", fullName:"Vitamines B1 (Thiamine) et B6 (Pyridoxine)", def:"Vitamines du groupe B. Supplementation dans le sevrage alcoolique et la denutrition.", expert:"B1 AVANT toute perfusion glucosee chez l'alcoolique (prevention encephalopathie de Gayet-Wernicke). Perfusion IV lente.", cat:"ABREV"},
{ term:"BIO / BIO G5%", fullName:"Bionolyte (solute glucose et electrolytes)", def:"Solute de nutrition de base apportant glucose, Na, K, Cl, Ca. Perfusion continue.", expert:"Controle glycemie regulier. Ne pas melanger avec medicaments incompatibles (insuline, amines).", cat:"ABREV"},
{ term:"CELO", fullName:"Celocurine (Suxamethonium)", def:"Curare depolarisant ultra-rapide (60 sec). Induction en sequence rapide (ISR) en intubation d'urgence.", expert:"Dose : 1-1.5 mg/kg IV. CI : hyperkaliemie, brulures etendues, traumatisme medullaire chronique. Decurarisation spontanee 8-10 min.", cat:"ABREV"},
{ term:"CG", fullName:"Culot Globulaire", def:"Produit sanguin labile. 1 culot environ 250 mL, eleve Hb d'environ 1 g/dL.", expert:"Seuil : Hb < 7 g/dL (8 si coronarien). Verification stricte : identite, groupe, RAI < 72H. Debit : 30-60 min/culot.", cat:"ABREV"},
{ term:"DIP / DPV", fullName:"Diprivan / Propofol", def:"Hypnotique IV a courte duree d'action. Standard de la sedation en reanimation.", expert:"PSE exclusif. Changer tubulure toutes les 12H (solution lipidique). Surveiller hypotension, bradycardie, hypertriglyceridemie. PRIS si > 5 mg/kg/h prolonge.", cat:"ABREV"},
{ term:"DOBU", fullName:"Dobutrex (Dobutamine)", def:"Catecholamine inotrope positive (beta1). Choc cardiogenique, bas debit.", expert:"Voie centrale obligatoire. Dilution : 250 mg dans 50 mL. Dose : 2-20 ug/kg/min. Tachycardie frequente. Ne pas associer avec solutions alcalines.", cat:"ABREV"},
{ term:"ETO", fullName:"Etomidate", def:"Hypnotique IV pour induction anesth. Hemodynamiquement stable. Patients instables.", expert:"Dose : 0.3 mg/kg IV. Inhibe synthese cortisol 4-8H. Myoclonies frequentes. Ne pas utiliser en entretien.", cat:"ABREV"},
{ term:"GENTA", fullName:"Gentamycine (Gentamicine)", def:"Aminoglycoside actif sur les BGN. Dose unique journaliere.", expert:"Dose : 3-5 mg/kg/j en 30 min. Nephrotoxique et ototoxique. Dosage residuel avant 3e injection. Incompatible avec les penicillines dans la meme seringue.", cat:"ABREV"},
{ term:"HNF", fullName:"Heparine Non Fractionnee", def:"Anticoagulant parenteral a action rapide. PSE continu ou prevention. Antagonisable par protamine.", expert:"TCA cible : 60-80 sec (2-2.5x temoin). Controle TCA toutes les 6H a l'initiation. Risque TIH (surveiller plaquettes). 25 000 UI dans 50 mL NaCl.", cat:"ABREV"},
{ term:"HSHC", fullName:"Hemisuccinate d'hydrocortisone (Hydrocortisone)", def:"Corticoide IV a action rapide. Choc septique refractaire, insuffisance surrenale, anaphylaxie severe.", expert:"Choc septique : 200 mg/j continu ou 50 mg/6H. Anaphylaxie : 200 mg IV direct. Surveiller glycemie et natremie.", cat:"ABREV"},
{ term:"MDZ / MIDA / HYPNO", fullName:"Midazolam / Hypnovel", def:"Benzodiazepine IV. Sedation, amnesie, anxiolyse. Standard en reanimation avec le propofol.", expert:"PSE. Accumulation si insuffisance renale/hepatique. Reversal : Flumazenil (Anexate). RASS cible : -1 a -2.", cat:"ABREV"},
{ term:"NAD / NA", fullName:"Noradrenaline (Norepinephrine)", def:"Catecholamine vasopresseur de 1ere intention en choc septique. Effet alpha-adrenergique (vasoconstriction).", expert:"Voie centrale OBLIGATOIRE. 4 mg ou 8 mg dans 50 mL G5%. Objectif PAM superieur ou egal a 65 mmHg. Arreter progressivement. Surveiller les extremites.", cat:"ABREV"},
{ term:"OE", fullName:"Oligoelements", def:"Micronutriments (zinc, selenium, cuivre, manganese) pour prevenir les carences en nutrition parenterale.", expert:"Zinc : cicatrisation. Selenium : immunite. Administres dans les poches de NP ou separement.", cat:"ABREV"},
{ term:"PFG", fullName:"Perfalgan (Paracetamol IV)", def:"Antalgique et antipyretique non morphinique. 1 g IV en 15 min toutes les 6H (4 g/j max).", expert:"Dose max : 3 g/j si insuffisance hepatique ou < 50 kg. Hepatotoxicite en surdosage. Voie IV si PO impossible.", cat:"ABREV"},
{ term:"PFC", fullName:"Plasma Frais Congele", def:"Produit sanguin labile apportant tous les facteurs de coagulation. Coagulopathies, CIVD, surdosage AVK.", expert:"1 poche environ 200-250 mL. Decongelation 20-30 min. Verification groupe ABO compatible, RAI. Debit : 30-60 min/poche.", cat:"ABREV"},
{ term:"PV / HPV", fullName:"Poly Vitamines", def:"Apport multivitaminique parenteral (A, B, C, D, E, K) a ajouter dans la nutrition parenterale.", expert:"Sensible a la lumiere (opacifier les tubulures). Ajouter systematiquement aux poches de NPT.", cat:"ABREV"},
{ term:"RL", fullName:"Ringer Lactate", def:"Solute cristalloide de remplissage iso-osmolaire, plus physiologique que NaCl 0.9%.", expert:"Composition proche du plasma. Prefere au NaCl 0.9% en grands volumes (evite acidose hyperchloremique). CI relative : hyperkaliemie.", cat:"ABREV"},
{ term:"SALBU", fullName:"Salbutamol", def:"Beta2-agoniste bronchodilatateur. Nebulisation ou IV en bronchospasme severe ou hyperkaliemie.", expert:"Bronchospasme : 5 mg nebulise. Hyperkaliemie aigue : 10-20 mg nebulise ou 0.5 mg IV sur 15 min (effet rapide, transitoire). Surveiller FC et glycemie.", cat:"ABREV"},
{ term:"SERUM / SSI", fullName:"Serum Physiologique (NaCl 0.9%)", def:"Solute sale isotonique universel pour perfusion, dilution medicaments, rincages.", expert:"Attention aux grandes quantites : acidose hyperchloremique. Standard de dilution pour antibiotiques et amines.", cat:"ABREV"},
{ term:"SUF", fullName:"Sufentanil", def:"Opioide de synthese 5-10x plus puissant que le Fentanyl. Analgesie en reanimation (PSE continu).", expert:"Dilution : 250 ug dans 50 mL NaCl = 5 ug/mL. Debit : 0.5-3 ug/kg/h. Accumulation possible. Reversal : Naloxone 0.4 mg IV. Surveiller RASS et CPOT.", cat:"ABREV"},
{ term:"TAZO", fullName:"Tazocilline (Piperacilline / Tazobactam)", def:"Beta-lactamine a large spectre (BGN, Pseudomonas, anaerobies). Infections nosocomiales severes.", expert:"Dose : 4 g/0.5 g toutes les 6H ou perfusion prolongee (3H). CI : allergie penicilline. Ajuster a la clairance renale.", cat:"ABREV"},
{ term:"TNT", fullName:"Trinitrine (Nitroglycerie)", def:"Derive nitre vasodilatateur. OAP, angor instable, HTA maligne.", expert:"PSE obligatoire. 10 mg dans 50 mL. Debit : 1-10 mg/h. Surveillance PA invasive. Tachyphylaxie rapide. CI : inhibiteurs PDE5 (Viagra).", cat:"ABREV"},
{ term:"VANCO", fullName:"Vancomycine", def:"Glycopeptide bactericide actif sur les CGP (SARM, Enterocques). Resistance aux beta-lactamines ou allergie.", expert:"Perfusion superieure ou egale a 60 min (syndrome homme rouge si rapide). Charge 25 mg/kg puis 30-45 mg/kg/j. Cible residuelle 15-20 ug/mL. Nephrotoxique. Ajuster a la clairance.", cat:"ABREV"},
/* ===== ABRÉVIATIONS — B. DISPOSITIFS ET EXAMENS ===== */
{ term:"BAT", fullName:"Bas Anti-Thrombose", def:"Contention mecanique prevenant la TVP chez le patient alite. Classe 2 minimum en reanimation.", expert:"Taille adaptee. Associer HBPM si pas de CI. Surveillance cutanee quotidienne.", cat:"ABREV"},
{ term:"BU", fullName:"Bandelette Urinaire", def:"Test rapide sur urines : nitrits, leucocytes, sang, glucose, proteines.", expert:"Valeur diagnostique limitee en reanimation (faux positifs frequents). Completer par ECBU si suspicion d'infection.", cat:"ABREV"},
{ term:"CPRE", fullName:"Cholangio-Pancreatographie Retrograde Endoscopique", def:"Endoscopie des voies biliaires et pancreatiques. Diagnostic et traitement (calculs, protheses).", expert:"Sous AG ou sedation profonde. Risques : pancreatite post-CPRE, perforation, hemorragie. Surveiller douleurs, fievre, amylase.", cat:"ABREV"},
{ term:"DEF", fullName:"Defibrillateur", def:"Choc electrique pour arythmies letales (FV, TV sans pouls). Test quotidien obligatoire.", expert:"Energie : 150-200 J biphasique (FV). Defibrillation le plus precoce possible en ACR.", cat:"ABREV"},
{ term:"DT", fullName:"Drain Thoracique", def:"Drain en espace pleural pour pneumothorax, pleurasie, hemothorax. Bocal Pleur-Evac.", expert:"Surveiller : oscillations, bullage, debit horaire. Ne JAMAIS clamper sans prescription. Asepsie stricte.", cat:"ABREV"},
{ term:"ECBU", fullName:"Examen Cytobacteriologique des Urines", def:"Analyse microbiologique des urines pour diagnostic d'infection urinaire.", expert:"Prelevement aseptique depuis SU ou mi-jet. Acheminer moins de 2H. Seuil : superieur a 103 UFC/mL sur SU. Antibiotherapie selon antibiogramme.", cat:"ABREV"},
{ term:"EEG", fullName:"Electro-Encephalogramme", def:"Enregistrement de l'activite electrique cerebrale. Epilepsie, encephalopathies, mort encephalique.", expert:"Indique si convulsions, trouble de conscience inexplique, bilan mort encephalique. Interpretation neurologique.", cat:"ABREV"},
{ term:"EMG", fullName:"Electromyogramme", def:"Exploration electrophysiologique des muscles et nerfs peripheriques.", expert:"Neuropathie de reanimation (CIP/CIM) frequente apres sejour prolonge. Retarde le sevrage ventilatoire.", cat:"ABREV"},
{ term:"ETT", fullName:"Echographie Trans-Thoracique", def:"Exploration cardiaque par ultrasons au lit du patient. Fonction cardiaque, valves, epanchements.", expert:"1ere exploration echocardiographique en urgence. Guide le remplissage et les amines. Couplee au Doppler.", cat:"ABREV"},
{ term:"FO", fullName:"Fond d'Oeil", def:"Examen visualisant la retine et le nerf optique. HTIC, HTA maligne.", expert:"Necessite mydriase. Chercher oedeme papillaire (HTIC) avant PL. Peut etre realise au lit.", cat:"ABREV"},
{ term:"FOGD", fullName:"Fibroscopie OesogastroDuodenale", def:"Endoscopie digestive haute. Oesophage, estomac, duodenum.", expert:"A jeun 6H. En urgence : hemorragie digestive haute. Aspiration active pendant le geste. Surveiller SpO2 et perforation.", cat:"ABREV"},
{ term:"GEP", fullName:"Gastrostomie Endoscopique Percutanee", def:"Sonde de nutrition dans l'estomac par voie endoscopique. Alternative SNG pour NE superieure a 4 semaines.", expert:"Soins de site quotidiens. Verifier position et permeabilite avant chaque administration. Mobilisation 360 deg quotidienne.", cat:"ABREV"},
{ term:"Gpe", fullName:"Groupe Sanguin (ABO-Rh)", def:"Determination du groupe sanguin indispensable avant toute transfusion.", expert:"2 determinations sur 2 prelevements distincts obligatoires. Validite 3 mois. O negatif en urgence vitale sans attendre.", cat:"ABREV"},
{ term:"Hb", fullName:"Hemoglobine", def:"Proteine des GR transportant l'O2. Normale : 12-16 g/dL (F), 13-17 g/dL (H).", expert:"Seuil transfusionnel : inferieur a 7 g/dL (8 si coronarien). Interpreter avec le contexte clinique.", cat:"ABREV"},
{ term:"HC / Hemocs", fullName:"Hemocultures", def:"Prelevement de sang sur flacons aerobie et anaerobie. Identification bacterienne ou fongique en cas de sepsis.", expert:"Avant toute antibiotherapie si possible. 2 paires sur 2 sites differents. Volume : 8-10 mL/flacon. Resultat positif = ALERTE immediate.", cat:"ABREV"},
{ term:"IOT", fullName:"Intubation Oro-Tracheale", def:"Mise en place d'une sonde dans la trachee par voie orale pour securiser les VAS et assurer la ventilation mecanique.", expert:"Verification : auscultation bilaterale, EtCO2, RP (tip 2-3 cm au-dessus carene). Fixer la sonde. Gonflage ballonnet 20-30 cmH2O.", cat:"ABREV"},
{ term:"KT", fullName:"Catheter", def:"Terme generique pour tout dispositif tubulaire insere dans un vaisseau ou une cavite pour perfusion, prelevement ou drainage.", expert:"Preciser systematiquement le type (VVP, CVC, KTA, KTD) dans les transmissions et la tracabilite. Surveiller le site a chaque tour.", cat:"ABREV"},
{ term:"KTA", fullName:"Catheter Arteriel", def:"Catheter en artere radiale ou femorale pour mesure continue de la PA invasive et prelevements arteriels.", expert:"Purge continue NaCl 0.9% pressurise a 300 mmHg. Surveiller l'aspect de la main (coloration, chaleur). Rincer apres chaque prelevement. Zero quotidien. Cf. protocole de service RD:PRO/SOIN/5-2/17.", cat:"ABREV"},
{ term:"KTD", fullName:"Catheter Dialyse (Shaldon)", def:"Catheter double lumiere de gros calibre (11-12F) pour epuration extrarenale (CVVH, hemodialyse).", expert:"Debits requis : 150-300 mL/min. Verrous heparine apres chaque seance. Risque infectieux eleve : asepsie stricte.", cat:"ABREV"},
{ term:"KTVC / KTC", fullName:"Catheter Veineux Central / Catheter Central", def:"Catheter long en veine profonde. PVC, perfusions multiples, drogues vasoactives.", expert:"Asepsie chirurgicale a la pose. Pansement J0, J2 puis 1x/semaine. RP systematique apres pose jugulaire/sous-claviere.", cat:"ABREV"},
{ term:"LBA", fullName:"Lavage Broncho-Alveolaire", def:"Prelevement bronchique sous fibroscopie. Diagnostic des PAVM.", expert:"Acheminer immediatement au laboratoire. Complication possible : desaturation, bronchospasme. Oxygenotherapie preventive.", cat:"ABREV"},
{ term:"NSE", fullName:"Enolase Neuro-Specifique", def:"Marqueur biologique de souffrance neuronale. Pronostic post-anoxie cerebrale (ACR) a H24, H48, H72.", expert:"NSE superieur a 33 ug/L a 24-48H = facteur pejoratif. Interpreter avec EEG et examen clinique dans un algorithme pronostique structure.", cat:"ABREV"},
{ term:"PDP", fullName:"Prelevement Distal Protege", def:"Prelevement bronchique par brosse protegee sous fibroscopie pour diagnostic de PAVM.", expert:"Seuil significatif : superieur ou egal a 103 UFC/mL. Plus specifique que l'aspiration tracheale standard.", cat:"ABREV"},
{ term:"PL", fullName:"Ponction Lombaire", def:"Prelevement de LCR par ponction L3-L4 ou L4-L5. Meningite, encephalite, hemorragie sous-arachnoedienne.", expert:"CI : HTIC (FO avant), coagulopathie severe. Position chien de fusil ou assise. Analyser rapidement : cytologie, biochimie, bacteriologie.", cat:"ABREV"},
{ term:"PM", fullName:"Pace Maker (Stimulateur Cardiaque)", def:"Stimulation cardiaque electrique externe ou implantable. Bradycardies symptomatiques.", expert:"PM externe : verifier capture (spike + QRS large), frequence et intensite. Eviter IRM si PM implante non compatible.", cat:"ABREV"},
{ term:"RAI", fullName:"Recherche d'Agglutinines Irregulieres", def:"Test immunologique avant transfusion. Anticorps anti-erythrocytaires. Validite 72H urgence, 3 semaines routine.", expert:"Obligatoire avant transfusion. O negatif en urgence vitale sans attendre. Resultat positif = appel EFS.", cat:"ABREV"},
{ term:"RG", fullName:"Residu Gastrique", def:"Volume aspire lors de la surveillance de la nutrition enterale. Tolerance digestive et risque d'inhalation.", expert:"RG superieur a 300-500 mL = suspendre NE temporairement, repositionner tete a 30 degres. Toujours reinjecter le residu sauf vomissement abondant.", cat:"ABREV"},
{ term:"RP", fullName:"Radiographie Pulmonaire", def:"Examen de reference au lit. Controle dispositifs invasifs et surveillance parenchymateuse.", expert:"Position IOT : 2-3 cm au-dessus de la carene. Tip CVC : jonction VCS/OD. Interpreter epanchements et condensations.", cat:"ABREV"},
{ term:"SNG", fullName:"Sonde Nasogastrique", def:"Sonde introduite par voie nasale jusqu'a l'estomac. NE, aspiration, medicaments.", expert:"Verifier position par RP ou pH inferieur a 5.5. Surélever tete a 30 degres minimum en NE. Changer toutes les 4-6 semaines.", cat:"ABREV"},
{ term:"SU", fullName:"Sonde Urinaire a Demeure", def:"Sonde vesicale a ballonnet. Recueil continu des urines et mesure de la diurese horaire.", expert:"Asepsie stricte a la pose. Nettoyage meat/sonde 2x/j. Ablation des que possible (reduction INECTU).", cat:"ABREV"},
{ term:"TAP", fullName:"TDM Thoraco-Abdomino-Pelvien", def:"Scanner TAP injecte pour bilan d'extension tumorale, infectieux ou traumatique.", expert:"Verifier fonction renale, allergie, Metformine avant injection PDC. Transport securise avec monitoring complet.", cat:"ABREV"},
{ term:"TDM", fullName:"Tomodensitometrie (Scanner)", def:"Exploration radiologique par rayons X en coupes.", expert:"Transport securise obligatoire en reanimation. Anticiper toutes les connexions et extensions. Medecin accompagnateur si instabilite.", cat:"ABREV"},
{ term:"TR", fullName:"Toucher Rectal", def:"Examen par voie anale. Tonus sphincterien, fecalomes, prostate.", expert:"Evaluation du transit en reanimation (constipation frequente sous opioides). Consigner les resultats.", cat:"ABREV"},
/* ===== ABRÉVIATIONS — C. DIVERS ===== */
{ term:"DPP", fullName:"Delta PP (Variation de la Pression Pulsee)", def:"Parametre dynamique de precharge-dependance. DPP superieur a 13% = le patient repondra au remplissage.", expert:"Valide uniquement en ventilation controlee, rythme sinusal, sans HTAP.", cat:"ABREV"},
{ term:"AA", fullName:"Air Ambiant", def:"Melange gazeux naturel (21% O2, 78% N2). Reference pour evaluer la reserve respiratoire.", expert:"Valeurs normales : PaO2 80-100 mmHg, SpO2 superieure ou egale a 95%, PaCO2 35-45 mmHg. Reduire progressivement O2 avant sevrage.", cat:"ABREV"},
{ term:"AC / FA", fullName:"Arythmie Cardiaque par Fibrillation Auriculaire", def:"Tachyarythmie supraventriculaire. La plus frequente en reanimation.", expert:"FC superieure a 150 + instabilite : CEE. Stable : amiodarone, digoxine. Anticoagulation si superieur a 48H. Chercher et traiter la cause.", cat:"ABREV"},
{ term:"AT", fullName:"Aspirations Tracheales", def:"Aspiration des secretions bronchiques via l'IOT. Prevention de l'obstruction bronchique.", expert:"Technique fermee preferee. Duree inferieure a 15 sec. Oxygener avant et apres. Surveiller SpO2, FC, PA.", cat:"ABREV"},
{ term:"BK", fullName:"Bacille de Koch (Mycobacterium tuberculosis)", def:"Agent de la tuberculose. Suspicion devant une pneumopathie atypique ou meningite.", expert:"Precautions aeriennes strictes (chambre pression negative, masque FFP2). BK tubage matinal 3 jours consecutifs.", cat:"ABREV"},
{ term:"BLSE", fullName:"Beta-Lactamase a Spectre Etendu", def:"Enzyme de resistance aux cephalosporines et penicillines. BMR prioritaire.", expert:"Precautions contact obligatoires. Chambre individuelle. ATB : Imipenem ou Ertapenem. Signalement hygiene.", cat:"ABREV"},
{ term:"BMR", fullName:"Bacterie Multi-Resistante", def:"Resistance a plusieurs familles d'antibiotiques. SARM, BLSE, EPC, Pseudomonas multi-R.", expert:"Signalement obligatoire. Precautions contact + air selon espece. Depistage a l'admission et hebdomadaire.", cat:"ABREV"},
{ term:"BPCO", fullName:"Bronchopneumopathie Chronique Obstructive", def:"Maladie respiratoire obstructive progressive. Principale cause de decompensation hypercapnique.", expert:"VNI en 1ere intention en decompensation aigue. Objectif SpO2 88-92% (eviter hyperoxie). Bronchodilatateurs, corticoides, antibiotiques cibles.", cat:"ABREV"},
{ term:"BS / BSg", fullName:"Bilan Sanguin", def:"Prelevements biologiques sanguins de surveillance en reanimation.", expert:"Standard : NFS, CRP, ionogramme, uree, creatinine, bilan hepatique, coagulation, GDS. Prelever via KTA si disponible.", cat:"ABREV"},
{ term:"CEE", fullName:"Choc Electrique Externe", def:"Defibrillation ou cardioversion electrique pour arythmies graves.", expert:"FV/TV sans pouls : defibrillation non synchronisee 150-200 J. Cardioversion : synchronisee. Sedation avant cardioversion programmee.", cat:"ABREV"},
{ term:"CP / CPA", fullName:"Contre-Pulsion Aortique", def:"Assistance mecanique intra-aortique. Augmente la perfusion coronaire et reduit la postcharge.", expert:"Choc cardiogenique refractaire. Surveillance horaire : courbe PA, position ballon (RP), pouls distaux, anticoagulation TCA 60-80s.", cat:"ABREV"},
{ term:"CVVH", fullName:"Hemofiltration Continue (CRRT)", def:"Epuration extrarenale continue. IRA du patient instable.", expert:"Machine ARTIS. Surveillance horaire : pressions circuit, debit, bilan substitution, anticoagulation. Ionogramme quotidien.", cat:"ABREV"},
{ term:"CVVHD", fullName:"Hemodiafiltration Continue", def:"Epuration extrarenale continue associant hemofiltration et dialyse.", expert:"Indications elargies : sepsis severe, acidose metabolique refractaire, intoxications. Surveillance identique a CVVH.", cat:"ABREV"},
{ term:"DCD", fullName:"Decede", def:"Constatation du deces. Demarches medicales, administratives et soutien de l'equipe.", expert:"Constatation medicale tracee, information famille, demarches medico-legales, protocole PMO (MAASTRICHT), soutien psychologique.", cat:"ABREV"},
{ term:"DD", fullName:"Decubitus Dorsal", def:"Position allongee sur le dos. Position de reference en reanimation.", expert:"Escarres (occiput, talons, sacrum). Alterner avec DLD/DLG toutes les 2-3H. Tete a 30 degres pour NE et prevention PAVM.", cat:"ABREV"},
{ term:"DLD / DLG", fullName:"Decubitus Lateral Droit / Gauche", def:"Position allongee sur le cote. Prevention escarres, drainage bronchique, kinesitherapie.", expert:"Changer toutes les 2-3H. Proteger les points d'appui. Fixer IOT avant mobilisation. Minimum 2 soignants.", cat:"ABREV"},
{ term:"DTS", fullName:"Desorientation Temporo-Spatiale", def:"Perte de reperes dans le temps et l'espace. Frequente en reanimation (delirium).", expert:"Evaluer avec CAM-ICU. Prevention : horloge visible, rythme jour/nuit, appels reguliers. Chercher et traiter la cause.", cat:"ABREV"},
{ term:"DV", fullName:"Decubitus Ventral", def:"Retournement a 180 degres pour ameliorer l'oxygenation dans le SDRA severe. Duree minimum : 16H.", expert:"Minimum 5 soignants. Verifier fixations IOT, CVC, catheters. Proteger visage, sternum, genoux. Efficacite prouvee sur mortalite.", cat:"ABREV"},
{ term:"EER", fullName:"Epuration Extra-Renale", def:"Terme generique : HDI, CVVH, CVVHD. IRA severe, hyperkaliemie, surcharge.", expert:"Continu (CVVH) si instable, HDI si stable. Surveillance anticoagulation et bilan entrees-sorties.", cat:"ABREV"},
{ term:"EP", fullName:"Embolie Pulmonaire", def:"Obstruction arterielle pulmonaire par un thrombus. Urgence medicale.", expert:"Dyspnee, SpO2 basse, tachycardie. Diagnostic : Angio-TDM. Traitement : thrombolyse si choc, HNF sinon.", cat:"ABREV"},
{ term:"ESA / ESV", fullName:"Extrasystole Auriculaire / Ventriculaire", def:"Battement cardiaque premature d'origine auriculaire ou ventriculaire.", expert:"ESV en salves ou phenomene R/T = risque FV. Corriger K+ et Mg2+. Chercher une ischemie sous-jacente.", cat:"ABREV"},
{ term:"GV", fullName:"Garde Veine", def:"Perfusion continue a tres faible debit (inferieur a 10 mL/h) pour maintenir une voie veineuse ouverte.", expert:"NaCl 0.9% ou G5% selon les medicaments. Verifier permeabilite et absence d'extravasation a chaque tour.", cat:"ABREV"},
{ term:"HDI", fullName:"Hemodialyse Intermittente", def:"Epuration extra-renale par diffusion en seances de 3-5H. Patient hemodynamiquement stable.", expert:"Acces vasculaire : KT dialyse ou fistule. Surveillance PA toutes les 15-30 min. Bilan poids avant/apres.", cat:"ABREV"},
{ term:"LATA", fullName:"Limitation et Arret des Therapeutiques Actives", def:"Decision collegiale de ne pas initier ou d'arreter des traitements actifs. Procedure Leonetti-Claeys.", expert:"Tracee obligatoirement au dossier (date, participants, motifs). Soins de confort maintenus. Information famille. Soutien equipe.", cat:"ABREV"},
{ term:"LN", fullName:"Lunettes Nasales (O2)", def:"Dispositif O2 nasal a faible debit (1-6 L/min). Confort superieur au masque.", expert:"FiO2 approximative : +4% par L/min (ex : 2 L/min egal environ 29%). Humidifier si debit superieur a 3 L/min.", cat:"ABREV"},
{ term:"LP", fullName:"Liberation Prolongee", def:"Forme medicamenteuse a liberation progressive. Ne JAMAIS ecraser (surdosage potentiel).", expert:"Si SNG indispensable : contacter la pharmacie pour forme alternative. Ex : Oxycontin LP, Topalgic LP.", cat:"ABREV"},
{ term:"MCE", fullName:"Massage Cardiaque Externe", def:"Compressions thoraciques en ACR pour maintenir la perfusion coronaire et cerebrale.", expert:"Profondeur : 5-6 cm. Frequence : 100-120/min. Ratio 30:2 sans IOT. Rotation toutes les 2 min.", cat:"ABREV"},
{ term:"MHC", fullName:"Masque Haute Concentration", def:"Masque a reservoir O2. FiO2 elevee (60-80%). Hypoxemies severes.", expert:"Debit minimum : 10-15 L/min pour gonfler le reservoir. Verifier absence de recirculation CO2.", cat:"ABREV"},
{ term:"NC / NE", fullName:"Non Connu / Non Evaluable", def:"Information absente dans le dossier (NC) ou parametre non evaluable dans l'etat du patient (NE).", expert:"Distinguer NC de NE. Preciser la raison du NE pour la continuite des soins.", cat:"ABREV"},
{ term:"NTBR", fullName:"Not To Be Resuscitated (Ne pas reranimer)", def:"Decision medicale de ne pas entreprendre de RCP en cas d'arret cardiaque.", expert:"Decision collegiale tracee au dossier. Distincte de la LATA. Directives anticipees a respecter. Soins de confort maintenus.", cat:"ABREV"},
{ term:"NO", fullName:"Monoxyde d'Azote (iNO)", def:"Gaz vasodilatateur pulmonaire selectif par inhalation. SDRA severe, HTAP.", expert:"Dose : 5-40 ppm. Sevrage progressif (rebond HTAP). Surveiller methemoglobine et NO2.", cat:"ABREV"},
{ term:"OF", fullName:"Optiflow (Oxygenotherapie a Haut Debit)", def:"O2 humidifie chauffe par canules nasales a haut debit (15-70 L/min).", expert:"Debuter a 30-40 L/min, titrer. Humidificateur a 37C. Ne pas retarder l'intubation si criteres HACOR.", cat:"ABREV"},
{ term:"P.O", fullName:"Per Os (Par Voie Orale)", def:"Administration medicamenteuse par voie orale. Voie preferentielle des que possible.", expert:"Des que deglutition securisee et transit fonctionnel : relais PO. Adapter les doses (biodisponibilite IV differente).", cat:"ABREV"},
{ term:"PEP / PEEP", fullName:"Pression Expiratoire Positive", def:"Pression positive en fin d'expiration sur le respirateur. Maintient les alveoles ouvertes.", expert:"PEEP elevee : ameliore oxygenation mais diminue retour veineux. Auto-PEEP possible en obstruction bronchique.", cat:"ABREV"},
{ term:"PMO", fullName:"Prelevement Multi-Organes", def:"Prelevement d'organes a visee de transplantation. Mort encephalique ou MAASTRICHT.", expert:"Protocole strict : diagnostic mort encephalique, avis Agence de Biomedecine, accord familles. Coordination infirmiere de prelevement.", cat:"ABREV"},
{ term:"Pst", fullName:"Pansement", def:"Protection et traitement d'une plaie ou d'un site invasif.", expert:"CVC/KTA : pansement J0, J2 puis 1x/semaine. IOT : naso-buccal a chaque soin de bouche. Escarres : adapte a la profondeur.", cat:"ABREV"},
{ term:"QSP", fullName:"Quantite Suffisante Pour", def:"Completer avec un solvant jusqu'a obtenir le volume ou la concentration souhaitee.", expert:"Ex : SUF 250 ug QSP 50 mL dans NaCl 0.9%. Toujours preciser le solvant et le volume final.", cat:"ABREV"},
{ term:"RDG", fullName:"Reanimateur De Garde", def:"Medecin reanimateur responsable lors de la garde. Interlocuteur medical principal hors heures ouvrables.", expert:"Numeros service : REA 1 poste 1862 / REA 2 poste 1822. Appel immediat en cas d'urgence vitale.", cat:"ABREV"},
{ term:"SAP / PSE / IVSE", fullName:"Seringue Auto-Pousseuse / Pousse-Seringue Electrique", def:"Dispositif motorise pour administration precise. Indispensable pour drogues vitales.", expert:"Verifier debit, seringue chargee, alarme occlusion. Relais obligatoire pour catecholamines. Changer tubulure toutes les 24-72H.", cat:"ABREV"},
{ term:"SARM", fullName:"Staphylocoque Dore Resistant a la Meticilline", def:"BMR majeure resistant aux beta-lactamines. Traitement : Vancomycine.", expert:"Precautions contact strictes. Chambre individuelle si possible. Depistage nez/aisselles/perinee. Signalement hygiene systematique.", cat:"ABREV"},
{ term:"SAS", fullName:"Syndrome d'Apnee du Sommeil", def:"Pauses respiratoires repetees pendant le sommeil. Frequent chez les patients obeses ou cardiaques.", expert:"Peut compliquer le sevrage ventilatoire. Favoriser VNI nocturne lors du sevrage. Reprendre traitement habituel (PPC).", cat:"ABREV"},
{ term:"SB", fullName:"Si Besoin (Prescription Conditionnelle)", def:"Prescription a realiser selon l'evaluation clinique infirmiere ou la demande du patient.", expert:"Verifier les criteres de declenchement. Tracer heure, dose et effet observe. Si utilise frequemment : reevaluation medicale.", cat:"ABREV"},
{ term:"SPO2", fullName:"Saturation Pulsee en Oxygene", def:"Mesure non invasive de la saturation en O2. Objectif : 94-98% (92-96% si BPCO).", expert:"Faussee par vasoconstriction, hypothermie, vernis a ongles, intox CO. Correlation GDS indispensable en cas de doute.", cat:"ABREV"},
{ term:"To", fullName:"Temperature", def:"Parametre vital de surveillance continue. Normale : 36.5-37.5C. Voie centrale (rectale, vesicale ou nasopharyngee).", expert:"Hyperthermie superieure a 38.5C : chercher foyer infectieux. Hypothermie inferieure a 36C : coagulopathie, arythmies. Post-ACR : normothermie stricte.", cat:"ABREV"},
{ term:"TV", fullName:"Tachycardie Ventriculaire", def:"Arythmie grave a QRS larges et rapides superieur a 100/min. Risque de degeneration en FV.", expert:"TV + instabilite : CEE synchronise. TV sans pouls : defibrillation. TV toleree : amiodarone IV, correction ionique.", cat:"ABREV"},
{ term:"UF", fullName:"Ultrafiltration", def:"Elimination de l'eau plasmatique lors de la dialyse ou hemofiltration.", expert:"Regle sur la machine. Hypotension si UF trop rapide. Objectif selon tolerance hemodynamique.", cat:"ABREV"},
{ term:"VC / VAC", fullName:"Ventilation Controlee / Volume Assiste Controle", def:"Tous les cycles delivres par le respirateur. Patient passif.", expert:"Necessite sedation profonde (RASS -3 a -5). VT 6 mL/kg PP, FR, FiO2, PEEP. Mode de choix en phase aigue du SDRA.", cat:"ABREV"},
{ term:"VS / VSAI", fullName:"Ventilation Spontanee / VS avec Aide Inspiratoire", def:"Le patient declenche lui-meme les cycles. VSAI : amplifie chaque inspiration.", expert:"Test de VS (SAT) : criteres stricts. RSBI = FR/VT (normal inferieur a 105). Succes = indication d'extubation.", cat:"ABREV"},
{ term:"VO", fullName:"Varice Oesophagienne", def:"Dilatation des veines de l'oesophage (hypertension portale). Risque de rupture hemorragique mortelle.", expert:"Hemorragie : Octreotide/Terlipressine, ballonnet Sengstaken-Blakemore, FOGD dans les 12H.", cat:"ABREV"},
/* ===== SIGNES DE PROGRAMMATION DES SOINS (RD:PRO/SOIN/5-2/11) ===== */
{ term:"Triangle / Signes de programmation", fullName:"Signes de programmation des soins (RD:PRO/SOIN/5-2/11)", def:"Symboles de tracabilite des soins. Triangle vide = a faire. Triangle plein = fait. Triangle entre parentheses = si besoin. Croix = non fait.", expert:"Protocole d'identification du service. Fleche montante = Augmentation. Fleche descendante = Diminution. Double fleche = Arret. Fleches > = En cours. v = Vitesse.", cat:"ABREV"},
/* ===== APPLICATION ===== */
{ term:"Pathologies", fullName:"Module Pathologies — Répertoire clinique intégré", def:"Fonctionnalité PulseUnit permettant de consulter les définitions de 400+ pathologies classées par système anatomique (22 systèmes). Accessible via Menu ☰ → Pathologies.", expert:"Systèmes couverts : cardiovasculaire, respiratoire, neurologique, rénal, digestif, hémato, endocrinien, infectieux, oncologique, musculo-squelettique, cutané, ophtalmologique, ORL, psychiatrique, obstétrical, pédiatrique, auto-immun, métabolique, toxicologique, traumatologique, iatrogène, génétique. Recherche par nom de pathologie ou filtrage par système (onglets). Utile pour les transmissions, révisions cliniques et onboarding des nouveaux agents.", cat:"APPLICATION"},
{ term:"Besoins caloriques", fullName:"Calculateur de besoins énergétiques journaliers", def:"Calculateur PulseUnit estimant les apports caloriques et protéiques quotidiens à partir du poids, de la taille, de l'âge et du sexe. Deux modes disponibles : Personne lambda et Réanimation / Hospitalier.", expert:"Mode lambda : métabolisme de base (Harris-Benedict) × facteur d'activité PAL (1.2 sédentaire → 1.9 très actif). Protéines 0.8–1.2 g/kg/j. Mode réa : facteur stress × facteur activité réduite. Protéines 1.3 g/kg/j. Hydratation 30 mL/kg/j. Accessible via Menu ☰ → Calculateurs → Besoins caloriques. Complément de l'évaluation diététique formelle.", cat:"APPLICATION"},
{ term:"Annuaire services", fullName:"Annuaire interne GHPSO — Les Services", def:"Module PulseUnit centralisant les numéros de poste internes des services du GHPSO (Creil + Senlis). Accessible via Menu ☰ → Les Services. 3 onglets : Annuaire alphabétique (défaut), Par étage, Favoris.", expert:"Onglet 📋 Annuaire : liste alphabétique du site sélectionné (Creil/Senlis), regroupée par lettre initiale (A→Z), avec index latéral sticky permettant de sauter à une lettre en 1 tap. Onglet 🏢 Par étage : étages distincts (7e → sous-sol → administration), chaque étage contient ses services (catégories) groupés à l'intérieur. Onglet ⭐ Favoris : numéros épinglés par étoile ☆, regroupés par site, persistance localStorage (clé pulseunit_svc_favs). Le résolveur d'étage parse à la fois le champ section.floor et la mention (Étage X) dans le nom de chaque entrée — un service multi-étages est ainsi correctement éclaté à son niveau réel. Barre de recherche filtre en temps réel sur nom, numéro et catégorie.", cat:"APPLICATION"},
{ term:"Note de lit", fullName:"Note structurée par lit — surveillance partagée + observations privées", def:"Note associée à un lit, accessible en double-tap sur la carte. 5 emplacements (Garde 1 à 5) par lit. Deux sections : grille de surveillance horaire 🤝 partagée entre l'IDE et l'AS du lit, et observations libres 🔒 privées par utilisateur. Durée de vie 7 jours.", expert:"Stockage Firestore (pulseunit/bednotes) sync onSnapshot multi-appareils, cache localStorage offline. Deux espaces dans le doc : bedNotesData[userId] = texte privé (clé slot_X:bedId), bedNotesData['__shared_survey__'][bedId]['slot_X'] = grille partagée avec lastEditorId. Affichage en continuité forward (createdAt ≤ shiftDate). Grille surveillance : 21 lignes (Hémodynamique : Température, TA, PAM, Pouls, Saturation, Dextro/Insuline, Hémocu, Diurèse, EVA — Ventilation : O₂ V/min, Repère IOT, VI, Ve, Vm, FIO₂, FR, PEP, Pp, Pcrête, AI, NO ppm) × 3 créneaux, horaires 10h/14h/18h (jour) ou 22h/02h/06h (nuit). Encart \"🤝 dernière modif. par X le ...\" sous le titre de la section. Lecture/écriture du partagé : IDE/AS assigné au lit + admin. Migration auto des survey privés (modèle v1) vers la section partagée au premier chargement.", cat:"APPLICATION"},
{ term:"Bourse d'échange", fullName:"Permutation de gardes en temps réel", def:"Module PulseUnit de petites annonces pour permuter une garde avec un collègue. Synchronisation Firestore en direct entre tous les utilisateurs connectés.", expert:"Workflow : ① Proposer (date + Jour/Nuit à céder, garde souhaitée optionnelle) → ② les collègues consultent les demandes ouvertes → ③ acceptation côté app. La permutation doit ensuite être validée par le cadre de santé. États : Ouvert · Proposition reçue · Accepté. Accessible via Menu ☰ → Bourse d'échange.", cat:"APPLICATION"},
{ term:"Planning & CA", fullName:"Calendrier annuel personnel — congés et heures", def:"Calendrier annuel individuel pour poser et suivre congés, repos compensateurs, heures supplémentaires et formations. Données strictement locales à l'appareil.", expert:"États gérés : travail (jour/nuit), CA (Congés Annuels), CAN1 (CA reportés N-1 — séparation auto par règle FPH : tout CA jan-mars = N-1, avril-décembre = année courante ; affichage identique vert + numéro Digihops scanné, distinction interne dans Suivi RH), HP (Hors Période), HPN1, RCV (Repos Compensateur Variable), RCVN1, Frac (Fractionnement), HS / HSJ / HSN (Heures Supp. générique / Jour / Nuit), RC (Récupération), RCN, RH (Repos Hebdomadaire), maladie, formation. Calcul automatique des soldes, contraintes décret 2002-8 (max 21j consécutifs jour / 22j nuit, fractionnement ≥3 périodes ≥5j), DJF (Dimanches/Jours Fériés) cochés pour le RCV.", cat:"APPLICATION"},
{ term:"Cadenas REA / USIP", fullName:"Verrouillage de l'attribution médicale", def:"Bouton 🔓/🔒 sur les cartes RÉA 1, RÉA 2 et USIP permettant de figer l'assignation des médecins et de leurs secteurs de chambres pour la garde en cours.", expert:"Réservé aux administrateurs. Une fois verrouillé, les autres utilisateurs ne peuvent plus modifier le médecin ni son sectoriel jusqu'à déverrouillage. Le statut est sauvegardé par garde (medLocked dans shiftHistory). Le verrouillage USIP entraîne la fermeture visuelle de la carte.", cat:"APPLICATION"},
{ term:"Checklist chambre", fullName:"Vérification matériel par lit", def:"Mini-checklist de 10 points (BAVU, alarmes scope, aspiration, oxygène, zéro KT, pression ballonnet, humidificateur…) accessible sous chaque lit via le numéro + barre de progression.", expert:"Sauvegardée par garde (h.checklists[bedId]). Modifiable uniquement par l'IDE / l'AS / l'IDE Tech assigné au lit. Barre orange = en cours, verte = complète. Inaccessible en mode lecture seule ou si la garde est verrouillée.", cat:"APPLICATION"},
{ term:"Tâches IDE Tech", fullName:"Traçabilité des tâches techniques par garde", def:"Liste filtrée selon le jour de la semaine et la période (jour/nuit) des tâches techniques que doit assurer l'IDE Tech. Cochage et progression sauvegardés par garde.", expert:"Tap sur la barre de progression de la carte IDE TECH (ouvre 📝 Tâches & Traçabilité, réservé à l'IDE Tech courant). Source window.TECH_TASKS, filtrée par shifts ('ALL', 'ALL-J', 'ALL-N', '<jour>-J/N'). Pourcentage affiché sur la carte (mini-barre type cl-bar-row). Persistance via h.techTasks. Utile pour la traçabilité réglementaire des contrôles de matériel.", cat:"APPLICATION"},
{ term:"Carte IDE TECH", fullName:"Carte d'affectation IDE Tech (design lit pur)", def:"Carte au design strictement identique à un lit, sans boutons d'actions : en-tête 'IDE TECH' + numéros ☎ 7125 / 6086, une seule barre de progression (tâches), et la pill IDE de l'agent positionné.", expert:"L'IDE qui prend le slot NE change PAS de rôle : elle reste IDE dans l'effectif (couleur et badge IDE) et reste sélectionnable pour un lit. Persistance : h.techIdeId. Comportement type chambre : sélectionne-toi puis tap pour te placer ; re-tap (toi sélectionné) pour libérer le slot ; double-tap (sans sélection, slot pris par soi) ouvre les notes 7-gardes (bedId virtuel tech_ide). Tap de la barre = ouverture des Tâches & Traçabilité (réservé à l'IDE Tech courant). La barre passe en '✓ OK' (vert) immédiatement à la 100ᵉ tâche cochée — rafraîchissement de la carte synchrone via renderApp() depuis toggleTask.", cat:"APPLICATION"},
{ term:"Tech Notes (chambre)", fullName:"Notes techniques par chambre — visibles IDE Tech uniquement", def:"Section 'NOTES TECH' interne au modal d'une chambre (lit), réservée à l'IDE Tech courant et à l'admin. Sert à logguer stock matériel, intervention biomed, particularités techniques d'une chambre. Chaque chambre avec une tech note non vide affiche une pastille violette 🛠 en haut à droite de la carte lit (visible uniquement par l'IDE Tech).", expert:"Persistance : bedNotesData.techNotes[bedId]['slot_X'] = { text, createdAt, updatedAt, lastEditorId, lastEditorName, editLog } — stockée Firestore (BEDNOTES_DOC.techNotes) + cache localStorage (pu_bn_tech). TTL 7 jours, log des modifs capé à 20 entrées. La pastille 🛠 est rendue par renderApp() via window.hasTechNotesForBed(bedId). Au login d'un IDE qui est l'IDE Tech de la garde courante, ou à la prise du slot tech (selfAssignTech / handleTechIdeTap), window.notifyTechIdeOfPendingNotes() déclenche un toast + un push notif local listant les chambres concernées (ex : 'RÉA 3, USIP 2'). Idempotence par garde via clé localStorage pu_techn_notif:<shiftKey>:<userId> — on ne re-notifie que si la liste change.", cat:"APPLICATION"},
{ term:"Procédures", fullName:"Checklists d'actes invasifs et table de dilutions", def:"Module regroupant 7 checklists d'actes (KTA, KTC, Intubation oro-trachéale, SNG en aspiration, SNG sans aspiration, Sonde urinaire à demeure, PDP) et une table interactive de dilutions des médicaments d'urgence + l'EER Citrate Prismaflex.", expert:"Checklists stateless (réinitialisées à chaque ouverture). Onglets dans une barre horizontalement scrollable. Table de dilutions : ~15 molécules courantes (Adrénaline, Noradrénaline, Amiodarone, Atracurium, Insuline, Héparine, Midazolam, Propofol…) avec voies (IVD/PSE/IVL), conservation et dilution standard GHPSO. Accessible via Menu ☰ → Procédures.", cat:"APPLICATION"},
{ term:"EER Citrate", fullName:"Calculateur Prismaflex citrate régional", def:"Calculateur de paramétrage de l'épuration extra-rénale en mode anticoagulation citrate régional sur générateur Prismaflex.", expert:"Saisie du poids → débits préconisés (sang, citrate, dialysat, calcium, UF). Arbres décisionnels pour ajustement du citrate selon Ca²⁺ post-filtre et du calcium selon Ca²⁺ ionisé patient. Compteur de changements de set/poches. Accessible via Menu ☰ → Procédures → Dilutions & EER, ou directement depuis Calculateurs.", cat:"APPLICATION"},
{ term:"Calculateurs cliniques", fullName:"Outils de calcul intégrés", def:"Suite de calculateurs cliniques utilisés au quotidien en réa : GCS, RASS, Score Waterloo, sevrage alcoolique, IBW, P/F (SDRA), Driving Pressure (ΔP), PAM, débit PSE, dose/kg, conversions mg↔mL, diurèse horaire, IMC, besoins caloriques, EER Citrate.", expert:"Chaque calculateur vit dans une tuile dédiée. Les résultats sont annotés (zones cibles, alertes seuils). Accessible via Menu ☰ → Calculateurs ou via la recherche globale.", cat:"APPLICATION"},
{ term:"Protocoles cliniques", fullName:"Procédures écrites en lecture seule", def:"Bibliothèque de protocoles GHPSO consultables : KTA (Pose, Prélèvement GDS, Pansement, Surveillance, Ablation) et Thermogard 3000 (hypothermie thérapeutique post-ACR à 34°C).", expert:"Lecture seule, pas de modification utilisateur. Accessible via Menu ☰ → Protocoles ou via la recherche globale (titre, mot-clé).", cat:"APPLICATION"},
{ term:"Simulateur Respirateur", fullName:"Bac à sable de paramétrage ventilatoire", def:"Module didactique permettant d'ajuster 6 paramètres ventilatoires et de visualiser leur impact sur 8 scénarios cliniques type (SDRA, BPCO, asthme aigu grave, post-op…).", expert:"Module pédagogique non connecté à un dispositif réel. Accessible via Menu ☰ → Simulateur Respirateur. Utile pour la formation et la révision des modes/paramètres.", cat:"APPLICATION"},
{ term:"Recherche globale", fullName:"Recherche transverse depuis le dashboard", def:"Barre de recherche en haut du tableau de bord interrogeant simultanément les services, le lexique, les protocoles et les pathologies.", expert:"Résultats regroupés par origine, cliquables. Ouvre directement la fiche concernée. Recherche tolérante aux accents et casse.", cat:"APPLICATION"},
{ term:"Garde de nuit à venir", fullName:"Préparation anticipée de la nuit", def:"En garde de jour, la nuit à venir (même date) apparaît en tête de la barre de gardes pour permettre à l'équipe de préparer l'effectif et l'attribution des lits avant 20h.", expert:"Onglet ajouté automatiquement par le module shift quand la période courante est 'jour'. Cliquable pour basculer dessus, modifications enregistrées sur la garde 'today-nuit' qui deviendra la garde courante à 20h.", cat:"APPLICATION"},
{ term:"Auto-connexion 7 jours", fullName:"Mémorisation de session courte durée", def:"Option 'Se souvenir' à la connexion : maintient la session active pendant 7 jours sur l'appareil utilisé.", expert:"Stockage chiffré local (token signé). Renouvelé à chaque ouverture de l'app. Dévalidé immédiatement après changement de PIN ou suppression du compte par l'admin. Désactivé par défaut sur les postes partagés.", cat:"APPLICATION"},
{ term:"Signaler un bug", fullName:"Remontée rapide de bugs via WhatsApp", def:"Raccourci Menu ☰ → Signaler un bug ouvrant une conversation WhatsApp pré-remplie pour décrire un problème rencontré.", expert:"Permet une boucle de feedback rapide pendant la phase Alpha. Inclut automatiquement la version de l'app et un horodatage.", cat:"APPLICATION"},
{ term:"Centre de notifications", fullName:"Cloche header — flux des alertes", def:"Cloche 🔔 dans l'en-tête affichant un badge rouge avec le nombre de notifications non lues. Tape dessus pour ouvrir le centre de notifs (liste chronologique).", expert:"Sources : bourse (annonces, propositions, acceptations), demandes de reset PIN (admin uniquement), rappels de positionnement de garde (08h05+08h20 jour, 20h05+20h20 nuit), réception de messages internes. Stockage Firestore (pulseunit/notifications) keyed par userId, sync onSnapshot multi-appareils, cache localStorage offline, TTL 30 jours. Boutons : Tout lu, Effacer, suppression individuelle (×). Bouton 🔔 Activer notifications système en bas du modal pour activer les Web Push.", cat:"APPLICATION"},
{ term:"Messages internes", fullName:"DM 1-à-1 persistants entre utilisateurs", def:"Messagerie privée 1-to-1 entre n'importe quels utilisateurs du roster. Accessible via Menu ☰ → 💬 Messages. Sync temps réel multi-appareils, persistance à vie.", expert:"Stockage Firestore (pulseunit/messages) keyed par convId (userIds triés joints par '__'). Liste des conversations triée par date du dernier message, pastille de non-lus, recherche destinataire pour démarrer une nouvelle conversation. Vue chat : bulles alignées droite (mine) / gauche (other), accusés de lecture (✓ envoyé / ✓✓ lu). Suppression manuelle d'un message ou d'une conversation entière (visible des deux côtés). Notif déclenchée automatiquement à la réception via applyMessagesSnapshot.", cat:"APPLICATION"},
{ term:"Web Push", fullName:"Notifications système (app fermée)", def:"Notifications navigateur affichées même quand PulseUnit est fermée, avec son et vibration. Activable au 1er login (popup 4s après connexion) ou depuis le centre de notifs.", expert:"Implémentation : Notification API + Service Worker v3 (handler notificationclick → focus app + postMessage de l'action). Son WebAudio inline 2 bips ascendants 880Hz/1320Hz (pas de fichier .mp3). Vibration [200,80,200]. Si l'app est visible : toast in-app + son + vibration uniquement (pas de notif système doublonnée). Sur iPhone : ne marche que si l'app est installée sur l'écran d'accueil (Safari → Partager → Sur l'écran d'accueil) — limitation iOS sur les Web Push hors PWA.", cat:"APPLICATION"},
{ term:"Rappel positionnement garde", fullName:"Notif auto si pas dans la garde", def:"Notification automatique envoyée à 08h05 + 08h20 (garde de jour) ou 20h05 + 20h20 (garde de nuit) si l'utilisateur n'est pas dans l'effectif de la garde courante.", expert:"Loop interval 60s vérifie l'heure courante et déclenche la notif dans une fenêtre +10 min après l'heure cible. Flag localStorage pu_shift_remind_<date>_<tag> évite les doublons quotidiens. Stop si l'utilisateur a déjà répondu 'oui' à la modale Travaillez-vous ou s'il est déjà dans activeStaffIds. Click sur la notif rouvre la modale work-status. Désactivé pour les comptes admin (admin_view).", cat:"APPLICATION"},
{ term:"Scan planning", fullName:"Import du planning par photo (Vision IA, 100% gratuit)", def:"Bouton 📷 « Importer mon planning par photo » placé juste au-dessus du mois de janvier dans l'onglet Calendrier du Planning. Permet d'importer son propre planning depuis une photo (planning papier ou écran). L'extraction est automatique : seule la ligne de l'utilisateur connecté est lue, les autres agents sont ignorés. Aucune case déjà saisie n'est écrasée.", expert:"UI : déplacé du header vers une CTA pleine largeur au-dessus du calendrier (.plan-scan-cta avec gradient aqua, titre + sous-titre explicatif), pour une meilleure découvrabilité. L'input file reste caché (#plan-scan-input) ; data-action='clickById:plan-scan-input' relaie le tap. Architecture serverless 100% gratuite : Cloudflare Worker (free tier 100k req/jour, no card) qui proxy vers Google Gemini Flash 2.0 (free tier 1500 req/jour, no card). Image envoyée en base64 + identité user (firstName/lastName), prompt système strict (états valides PulseUnit + variantes orthographiques du nom). Réponse JSON {found, states: {YYYY-MM-DD: state}}. Côté Worker : retry exponentiel + jitter (1.5s/3s/6s + 0-2s aléatoire) sur 429 Gemini → 100 scans simultanés étalés sur ~7 min sans erreur. Origin allowlist sur pulseunit-c9c5c.web.app. Côté client : merge non-destructif (jamais d'écrasement d'une case déjà saisie), snapshot avant import, toast persistant 15s avec bouton Annuler pour rollback en un tap. Clé Gemini stockée en Cloudflare Worker secret (jamais côté client). Limite image 8 Mo.", cat:"APPLICATION"},
{ term:"Suivi RH", fullName:"Onglet Suivi RH du Planning — compteurs et débit/crédit", def:"Second onglet de la vue Planning (à côté de 📅 Calendrier) regroupant les compteurs de congés (CA, CA-HP, Fractionné, RCV), les transmissions cumulées, le tableau débit/crédit mensuel style Digihops, les alertes CA consécutifs et l'aperçu annuel. Sur l'année courante, tout est arrêté à la date du jour : seuls les CA et heures déjà réalisés comptent (les jours futurs planifiés ne sont pas inclus).", expert:"Construit autour du moteur PlanEngine (engine.js, fonctions pures) consommé par renderSuiviRH() dans planning-ca/handlers.js. Bornage temporel : un paramètre untilDate (YYYY-MM-DD) propagé à soldesPostes / yearlyRecap / yearlyDebitCreditTable / consecutiveCAPeriods / theoreticalHoursForMonth / realizedHoursForMonth / transmissionHours filtre les jours postérieurs ; sur l'année courante untilDate=todayStr, sur une année close pas de bornage, sur une année future untilDate=YYYY-1-12-31 (rien réalisé). Caps auto-calculés (Décret 2002-8) : CA = 25 strict, CA-HP = 0/1/2 selon nb de CA hors 1er mai-31 oct (≥5 → +1, ≥8 → +2), Fractionné = 0/1/2 selon nb de fractions ≥5j ouvrés (≥3 → +1, ≥4 → +2). Cards de compteurs : barres de progression posés/restants + ligne reliquat N-1 si > 0, bordure colorée par catégorie (CA=as, CA-HP=indigo, Frac=rose, RCV=vert), passage en rouge si dépassement de capital. RCV grisé si non éligible (<20 DJF travaillés ou profil nuit fixe). Tableau débit/crédit : 12 lignes mensuelles (mois | débit/crédit | cumul) avec coloration rouge/vert selon signe ; les mois futurs montrent dc=0 et cumul stagne au cumul du mois courant. Mise à jour automatique à l'ouverture de l'onglet et à chaque cyclage de case dans le Calendrier (via switchPlanTab → renderSuiviRH). Source de vérité = planStates + planSoldes + window.userProfile.agentType. Bouton 📄 PDF déclenche exportSuiviRHPdf() qui adapte la sortie de yearlyRecap() au format attendu par PlanPdfExport (même bornage à aujourd'hui).", cat:"APPLICATION"},
{ term:"Type d'agent", fullName:"Profil agent — Jour fixe / Nuit fixe / Alterné", def:"Caractéristique du profil utilisateur déterminant le calcul des heures théoriques mensuelles. Configuré via Menu ☰ → 👤 Mon compte → onglet Profil. Trois valeurs possibles : Jour fixe (35h hebdo, repos fixes), Nuit fixe (32h30 hebdo, ≥90% nuit), Alterné (mix jour/nuit, base 35h).", expert:"Source réglementaire : Guide du Temps de Travail GHPSO 2014, chapitre 1.4 (cycles de travail effectif). PlanEngine.theoreticalHoursForMonth(year, month, profile) calcule : nb jours ouvrés du mois (hors WE et fériés via getJoursFeries) × heures/jour selon profil (7h jour fixe, 6h30 nuit fixe, 7h alterné). Stockage : window.userProfile dans PLANS_DOC.{userId}.profile + localStorage pulseunit_user_profile_<userId>. Migration douce : si planRegime existant = 'nuit' à la 1ère ouverture après MAJ, agentType auto-pré-rempli en 'nuit-fixe' (le user peut corriger).", cat:"APPLICATION"},
{ term:"Mon compte", fullName:"Modale unifiée Profil + Paramètres + Déconnexion (4 onglets)", def:"Entrée unique du menu burger (Menu ☰ → 👤 Mon compte) qui regroupe en 4 onglets tout ce qui concerne l'utilisateur : 👤 Profil (Identité au format NOM Prénom + Type d'agent), 🎨 Préférences (thème, sons, haptique, ne pas déranger), 🔐 Sécurité (modifier mon code PIN, accès Admin), ... Plus (partager & installer, revoir tutoriel, export RGPD, lien Confidentialité). Le bouton 🚪 Se déconnecter reste fixé en bas de la modale, toujours visible quel que soit l'onglet, avec mini-confirm en 2 clics pour éviter les déconnexions accidentelles.", expert:"Modale #account-modal avec layout flex column : header fixe + tab nav (border-bottom aqua sur l'onglet actif, scroll horizontal sur petit écran) + zone panel scrollable (flex:1) + footer rouge fixe avec mini-confirm logout. Switch d'onglet via switchAccountTab(name) qui toggle .is-active sur le bouton et show/hide les panels #acc-panel-*. Tous les IDs internes (profile-name, profile-role, profile-type-card-*, theme-btn-*, setting-sound/haptic/dnd) sont conservés depuis les anciennes modales pour ne casser aucun handler JS. Aliases backwards-compat : window.openProfile = window.closeProfile = window.openSettings → openAccount/closeAccount, ce qui permet aux anciens callers (bouton ⚙️ Profil dans Suivi RH) de continuer à fonctionner. Mini-confirm logout : flag global window.__logoutSkipConfirm court-circuite le confirm() natif de logoutUser quand l'UI in-app a déjà confirmé. Identité affichée en format NOM Prénom (lastName en majuscules + firstName) pour matcher le libellé.", cat:"APPLICATION"},
{ term:"Débit / Crédit horaire", fullName:"Solde mensuel et cumul annuel des heures travaillées", def:"Différence entre les heures réellement travaillées et les heures théoriques attendues sur un mois donné. Positif = crédit (l'agent a fait plus que prévu), négatif = débit. Affiché dans l'onglet Suivi RH du Planning, format Digihops (HHhMM avec signe).", expert:"Calcul PlanEngine.monthlyDebitCredit() : realizedHours - theoreticalHours pour le mois. realizedHours somme par jour : jour=7h30, nuit=10h, hs/hs_j/hs_n=7h, formation=7h, ferie travaillé=7h30. Cumul annuel = somme glissante des débits/crédits mensuels (cf. capture Digihops 'Débit et crédit'). Permet de visualiser les dérives par rapport au temps contractuel et d'anticiper les régularisations RH. Le solde affiché ne comprend pas la 'Cumul Reste RTT' Digihops (à 0 par défaut chez Dimitri, hors champ pour cette refonte).", cat:"APPLICATION"},
{ term:"Transmissions cumulées", fullName:"Heures de transmission accumulées sur l'année", def:"Compteur du temps de transmission accumulé : 0h25 (15 minutes) par garde travaillée (J + N + HSJ + HSN). Affiché dans l'onglet Suivi RH, format 'Xh YYmin'.", expert:"Règle métier GHPSO : chaque IDE/AS a droit à 15 min de transmission par poste pour la passation entre équipes. PlanEngine.transmissionHours(year, planStates) compte les états jour/nuit/hs_j/hs_n et multiplie par 0.25h. Ces heures sont récupérables (mécanisme RC) ou intégrées dans le débit/crédit. Voir aussi le terme Transmission (catégorie PERSONNEL).", cat:"APPLICATION"},
{ term:"CA consécutifs", fullName:"Détection des périodes de CA enchaînées", def:"Liste automatique des périodes de congés annuels consécutives sur l'année. Affichée dans l'onglet Suivi RH avec alerte visuelle si une période dépasse 31 jours calendaires (limite GHPSO chap. 2.2 du Guide DRH 2014).", expert:"PlanEngine.consecutiveCAPeriods() détecte les séquences d'états ca/can1/ca_hp/ca_hpn1/frac/fracn1. Les états rh, rc, rcn n'interrompent PAS la période (allongement en lengthCalendarDays). Une période s'arrête à la rencontre d'un jour travail/jour/nuit/hs*/formation/ferie. Affichage : badge orange ⚠️ proche limite (>= 22j), bordure rouge si > 31j calendaires. Permet de respecter la limite réglementaire 'pas plus de 31 jours consécutifs' (exclusion HS dans ce cas).", cat:"APPLICATION"},
{ term:"Export PDF récap", fullName:"Récapitulatif annuel exportable en PDF", def:"Bouton 📄 PDF dans l'onglet Suivi RH générant un récapitulatif annuel exportable (compteurs, débit/crédit mensuel, jours travaillés, primes week-end, CA consécutifs). Nom de fichier : PulseUnit_recap_{année}_{nom}_{prénom}.pdf.", expert:"Implémentation PlanPdfExport.exportYearlyRecap() avec jsPDF 2.5.2 + plugin autoTable 3.8.4 chargés dynamiquement depuis cdn.jsdelivr.net (mis en cache PWA best-effort via API caches). Génère un PDF A4 portrait, marges 15mm, 7 sections : en-tête (titre + identité + date), compteurs congés, heures travaillées (totaux + tableau mensuel), jours travaillés/repos, primes & spécial (fériés, samedis+dimanches, transmissions), CA consécutifs, pied de page. Adapter dans handlers.js convertit la sortie engine (daysWorked/daysOff/totalRealizedHours…) en shape attendue par le module PDF (counts/totalRealized/totalTheoretical…). Si offline et CDN non en cache → toast d'erreur.", cat:"APPLICATION"}
  ];
